// Format: { s: "affirmation", v: true|false, e: "explication" }
// ~15% théoriques, ~85% cas pratiques

const MODULES = [
  {
    id: 1,
    titre: "Responsabilité pénale de l'IF et du CO",
    description: "Art. 305bis/ter CP, position de garant, cas pratiques de responsabilité",
    questions: [
      // — THÉORIE (3) —
      { s: "Dans les cas graves (blanchiment par métier, organisation criminelle), l'art. 305bis al. 2 CP prévoit une peine privative de liberté pouvant aller jusqu'à 5 ans.", v: true, e: "Exact : art. 305bis al. 2 CP — 5 ans de privation de liberté au plus (et non 7), assortis d'une peine pécuniaire de 500 jours-amende." },
      { s: "L'art. 305ter al. 2 CP crée une obligation absolue de signalement des soupçons au Ministère public.", v: false, e: "Faux : l'art. 305ter al. 2 CP crée un droit facultatif de communication (Anzeigerecht) — l'IF peut communiquer mais n'y est pas obligé, à la différence de l'art. 9 LBA qui crée une obligation." },
      { s: "Pour être poursuivi au titre de l'art. 305bis CP, l'auteur doit avoir agi avec intention directe ou dol éventuel ('savait ou devait présumer').", v: true, e: "Exact : l'art. 305bis CP requiert l'intention ou le dol éventuel. La simple négligence suffit en revanche pour l'art. 305ter CP (défaut de vigilance)." },
      // — CAS PRATIQUES (15) —
      { s: "Cas Adam/Bertrand — Bertrand (CO) a refusé d'examiner la transaction de CHF 495'000 portée sur un compte dont les mouvements habituels n'excèdent pas CHF 8'000. Il ne peut pas être tenu pénalement responsable car il n'était pas présent au guichet au moment du dépôt.", v: false, e: "Faux : Bertrand peut être tenu responsable au titre de l'art. 305ter CP — son refus délibéré d'examiner une transaction manifestement suspecte constitue précisément le défaut de vigilance, indépendamment de sa présence physique au guichet." },
      { s: "M. Meier est RM dans une banque de détail. Son client habituel (mouvements max CHF 12'000/mois) dépose CHF 480'000 en espèces. M. Meier exécute le dépôt sans signalement car 'le client est de confiance depuis 10 ans'. M. Meier risque une poursuite pénale.", v: true, e: "Exact : la confiance dans un client de longue date ne dispense pas de l'obligation de vigilance. Une telle transaction est manifestement suspecte — l'inaction constitue un défaut de vigilance (art. 305ter CP)." },
      { s: "Mme Favre est Compliance Officer. Elle apprend depuis 3 mois par son équipe qu'un RM accepte régulièrement des dépôts importants en espèces sans vérification KYC. Elle n'agit pas en attendant 'une preuve plus solide'. Elle ne peut pas être tenue pénalement responsable car les décisions KYC relèvent du RM.", v: false, e: "Faux : en tant que CO, Mme Favre est en position de garant (Garantenstellung). Son inaction délibérée face à des violations LBA connues depuis 3 mois engage sa responsabilité pénale (art. 305ter, voire art. 305bis CP par dol éventuel)." },
      { s: "La FINMA a ouvert une procédure d'interdiction d'exercer contre le directeur d'une banque. Pour que cette sanction soit valide, la FINMA doit d'abord obtenir une condamnation pénale préalable.", v: false, e: "Faux : la FINMA peut prononcer une interdiction d'exercer indépendamment de toute procédure pénale — elle doit prouver la responsabilité directe, individuelle et causale de la personne dans une grave violation du droit de la surveillance." },
      { s: "Un client effectue des dépôts en espèces de CHF 490'000 chaque mois depuis 14 mois, toujours juste sous le seuil d'alerte automatique de la banque. Ce schéma répétitif peut caractériser un blanchiment 'par métier' au sens de l'art. 305bis al. 2 CP.", v: true, e: "Exact : le blanchiment 'par métier' implique une activité systématique et répétée. Ce schéma de fractionnement sur 14 mois correspond aux critères de répétition et d'organisation caractérisant le blanchiment par métier." },
      { s: "Un RM accepte une relation avec un client dont le patrimoine déclaré (CHF 20 millions) est manifestement incohérent avec ses revenus professionnels connus (CHF 80'000/an), au motif que 'la marge est très attractive'. Il peut être poursuivi pour blanchiment (art. 305bis CP) sur la base du dol éventuel.", v: true, e: "Exact : accepter consciemment le risque que les fonds soient d'origine criminelle pour des raisons commerciales constitue le dol éventuel de l'art. 305bis CP ('savait ou devait présumer')." },
      { s: "Une banque suisse a traité des fonds provenant d'une corruption commise en Colombie. La Colombie punit également la corruption. Ces actes de blanchiment commis en Suisse ne sont pas punissables car l'infraction préalable s'est produite à l'étranger.", v: false, e: "Faux : art. 305bis al. 3 CP — le blanchiment est punissable en Suisse dès lors que l'infraction préalable est également punissable dans l'État où elle a été commise (double incrimination). La localisation de l'infraction préalable est sans pertinence." },
      { s: "M. Blanc est RM. Il soupçonne depuis 6 semaines que les fonds de son client sont liés à une fraude. Il attend 'd'avoir la certitude absolue' avant de signaler. Il n'a commis aucune faute car il agit avec prudence.", v: false, e: "Faux : l'art. 9 LBA impose une communication 'sans délai' dès que l'IF 'sait ou présume'. Attendre 6 semaines pour une 'certitude absolue' viole cette obligation — le soupçon fondé suffit, la certitude n'est pas requise." },
      { s: "Une fiduciaire a transféré CHF 1,2 million pour un client sans vérifier l'origine des fonds. Le client lui avait affirmé verbalement que 'tout est légal'. La fiduciaire peut se prévaloir de cette déclaration comme cause exonératoire en cas de poursuites.", v: false, e: "Faux : une déclaration verbale non documentée ne suffit pas à exonérer l'IF. L'art. 305ter CP impose une vérification raisonnable des faits — se contenter d'une affirmation orale non vérifiable constitue un défaut de vigilance." },
      { s: "Le CO d'une banque signe un rapport d'audit certifiant que les procédures LBA sont respectées, alors qu'il sait que ce n'est pas le cas. Ce comportement peut constituer la base d'une responsabilité pénale personnelle.", v: true, e: "Exact : certifier sciemment une situation fausse en matière LBA constitue une violation grave des obligations légales et peut engager la responsabilité pénale personnelle du CO selon les circonstances (art. 305bis/ter CP)." },
      { s: "Dans le cas Julius Baer, la FINMA a relevé que des RM recevaient des bonus uniquement liés à la croissance commerciale, ce qui pouvait les inciter à négliger leurs obligations LBA. Ce type d'incitation crée un risque pénal indirect pour l'institution.", v: true, e: "Exact : des incitations inopportunes créent un environnement où la compliance LBA cède face aux intérêts commerciaux — la FINMA a sanctionné Julius Baer notamment pour cette culture compliance lacunaire." },
      { s: "Un IF suisse est exonéré de toute responsabilité pénale si ses procédures LBA internes sont formellement correctes sur papier, même si elles ne sont pas appliquées en pratique.", v: false, e: "Faux : la responsabilité pénale (art. 102 CP pour les personnes morales, art. 305bis/ter CP pour les personnes physiques) tient à l'application effective des mesures — des procédures non suivies en pratique n'exonèrent pas l'IF." },
      { s: "Un avocat zurichois reçoit CHF 300'000 en espèces d'un client pour financer l'achat d'un bien immobilier. Il soutient que le secret professionnel le protège de toute obligation LBA dans cette transaction.", v: false, e: "Faux : les avocats sont assujettis à la LBA pour les activités financières (gestion de fonds, transactions immobilières) — le secret professionnel ne les exempte pas de leurs obligations de diligence LBA dans ce contexte." },
      { s: "Dans une procédure LBA grave, la FINMA, le Ministère public et les autorités civiles peuvent chacun intervenir simultanément avec des pouvoirs distincts.", v: true, e: "Exact : une particularité des affaires LBA est la possible intervention concurrente de plusieurs autorités — FINMA (surveillance), Ministère public (pénal), tribunaux civils (restitution des avoirs)." },
      { s: "Un directeur de banque qui a mis en place de bonnes procédures LBA mais n'a pas assuré leur contrôle effectif peut être tenu personnellement responsable si des violations LBA systématiques se produisent dans son établissement.", v: true, e: "Exact : la responsabilité du dirigeant inclut la surveillance effective de l'application des procédures — déléguer sans contrôler ne suffit pas à s'exonérer en cas de défaillance systémique." }
    ]
  },
  {
    id: 2,
    titre: "Blanchiment d'argent sous l'angle du Code pénal",
    description: "Art. 305bis CP, infractions préalables, auto-blanchiment, cas pratiques CP",
    questions: [
      // — THÉORIE (3) —
      { s: "L'infraction de blanchiment (art. 305bis CP) est consommée dès que l'acte est objectivement 'propre à entraver' la confiscation, même si la confiscation n'est pas effectivement empêchée.", v: true, e: "Exact : c'est une infraction de résultat formel — consommée par l'acte d'entrave, peu importe son efficacité réelle." },
      { s: "En droit suisse, l'auto-blanchiment par l'auteur de l'infraction préalable n'est pas punissable.", v: false, e: "Faux : l'auto-blanchiment est punissable en droit suisse — l'auteur de l'infraction préalable (trafic de drogue, corruption, etc.) peut également être poursuivi pour blanchiment des produits de son crime." },
      { s: "Le délit fiscal qualifié constitue une infraction préalable au blanchiment uniquement si la soustraction fiscale dépasse CHF 300'000 par période fiscale.", v: true, e: "Exact : art. 305bis al. 1bis CP — seuil de CHF 300'000 par période fiscale (art. 186 LIFD / art. 59 al. 1 LHID). La soustraction fiscale ordinaire ne suffit pas." },
      // — CAS PRATIQUES (15) —
      { s: "ATF 136 IV 188 (Cocoteros) — Les fonctionnaires A., B. et C. ont été condamnés pour corruption passive. Les pots-de-vin qu'ils ont reçus constituent l'infraction préalable au blanchiment reproché à la banque D.", v: true, e: "Exact : la corruption passive des fonctionnaires est l'infraction préalable. La banque D. et ses collaborateurs ont été impliqués dans le blanchiment de ces fonds d'origine criminelle." },
      { s: "Mme X est l'épouse d'un homme poursuivi pour fraude fiscale (soustraction de CHF 450'000 sur 2 ans). Elle signe un formulaire A déclarant être l'ayant droit économique des fonds qui appartiennent en réalité à son mari. Cet acte constitue du blanchiment.", v: true, e: "Exact : remplir un faux formulaire A pour dissimuler l'identité réelle de l'ADE est un acte 'propre à entraver' l'identification de l'origine des fonds — acte de blanchiment (art. 305bis CP)." },
      { s: "M. Gerber informe son gérant de fortune que CHF 280'000 de son revenu annuel proviennent d'une activité commerciale non déclarée aux impôts. Cette soustraction fiscale de CHF 280'000 par période fiscale constitue un délit fiscal qualifié susceptible de fonder un blanchiment.", v: false, e: "Faux : CHF 280'000 par période fiscale est inférieur au seuil légal de CHF 300'000 — il ne s'agit pas d'un délit fiscal qualifié au sens de l'art. 305bis al. 1bis CP. La soustraction simple ne suffit pas." },
      { s: "Dans l'ATF 136 IV 188, la banque D. a argué qu'elle ignorait l'origine des fonds versés par les fonctionnaires. Le Tribunal fédéral a retenu le dol éventuel — la banque 'aurait dû présumer' l'origine douteuse des fonds au vu des circonstances.", v: true, e: "Exact : le dol éventuel ('savait ou devait présumer') est suffisant pour l'art. 305bis CP. La banque D. devait reconnaître les indices d'une origine douteuse — l'ignorance 'volontaire' ne suffit pas à l'exonérer." },
      { s: "M. Dupont, avocat, reçoit CHF 400'000 en espèces d'un client et les répartit sur 4 comptes de CHF 100'000 dans différentes banques suisses, pour 'commodité de gestion'. Ce fractionnement peut constituer du structuring (smurfing).", v: true, e: "Exact : le structuring consiste à fractionner intentionnellement des fonds pour contourner les seuils de surveillance ou de déclaration — ce comportement caractérise un acte de blanchiment." },
      { s: "Un client réalise annuellement CHF 350'000 de recettes non déclarées en France, où la fraude fiscale est également punissable. Ces fonds transférés en Suisse peuvent constituer des produits d'une infraction préalable au blanchiment.", v: true, e: "Exact : CHF 350'000 par période fiscale dépasse le seuil de CHF 300'000. De plus, art. 305bis al. 3 CP : les infractions préalables commises à l'étranger sont prises en compte si elles sont également punissables dans cet État." },
      { s: "Un intermédiaire panaméen envoie CHF 8 millions à une banque suisse avec comme seul motif 'commission d'investissement', sans identifier le donneur d'ordre final. La banque suisse peut traiter ce virement si le montant est conforme au profil de l'IF panaméen.", v: false, e: "Faux : l'IF est tenu d'identifier le donneur d'ordre final (ADE) et de comprendre l'arrière-plan économique de la transaction. L'absence d'identification du donneur d'ordre constitue un défaut de vigilance, quel que soit le montant." },
      { s: "Un trafiquant de drogue qui blanchit lui-même les produits de son trafic via des investissements immobiliers peut être poursuivi à la fois pour trafic de drogue (infraction préalable) et pour blanchiment.", v: true, e: "Exact : l'auto-blanchiment est punissable en Suisse — le trafiquant peut être condamné pour son infraction préalable ET pour les actes de blanchiment des produits de celle-ci." },
      { s: "Mme K., directrice d'une société de négoce, reçoit un paiement de CHF 250'000 en espèces d'un acheteur inconnu provenant d'un pays figurant sur la liste noire du GAFI. Si elle accepte ce paiement sans diligences, elle s'expose à une poursuite au titre de l'art. 305ter CP.", v: true, e: "Exact : les espèces importantes provenant d'un pays GAFI blacklisté constituent des indices manifestes — ne pas effectuer de diligences constitue un défaut de vigilance (art. 305ter CP)." },
      { s: "Dans le cas pratique (module 2), Mme X a remis un formulaire A falsifié. La banque qui a accepté ce formulaire sans vérification de plausibilité (alors que le contexte était clairement suspect) peut être tenue partiellement responsable.", v: true, e: "Exact : l'IF ne peut pas se contenter d'accepter un document sans vérifier sa plausibilité — une vérification minimale de cohérence s'impose, particulièrement dans un contexte suspect." },
      { s: "Un banquier qui a aidé un client à placer CHF 5 millions d'origine criminelle peut être poursuivi pour blanchiment même si l'infraction préalable (trafic de drogue) remonte à 10 ans avant les actes de blanchiment.", v: true, e: "Exact : la prescription de l'acte de blanchiment court à partir des actes de blanchiment eux-mêmes, non de l'infraction préalable — un banquier peut donc être poursuivi même si le crime source est ancien." },
      { s: "Un client présente une attestation de son notaire certifiant la légalité de ses fonds. La banque est totalement exonérée de toute responsabilité LBA si elle se fie à cette attestation.", v: false, e: "Faux : une attestation d'un tiers (même un notaire) ne dispense pas l'IF de sa propre évaluation de plausibilité. La responsabilité de la vérification reste avec l'IF — l'attestation est un élément parmi d'autres, pas une exonération totale." },
      { s: "La manipulation de cours de bourse (art. 143 LIMF) et le délit d'initié (art. 142 LIMF) constituent des infractions préalables au blanchiment d'argent.", v: true, e: "Exact : la LIMF prévoit ces infractions préalables liées aux marchés financiers — leurs produits peuvent donc constituer des fonds blanchissables au sens de l'art. 305bis CP." },
      { s: "Un client français a soustrait CHF 320'000 d'impôts par an en France pendant 3 ans. Il transfère ces fonds (CHF 960'000 au total) en Suisse. Chaque période fiscale (CHF 320'000) dépasse le seuil — il s'agit d'un délit fiscal qualifié pouvant fonder un blanchiment.", v: true, e: "Exact : le seuil de CHF 300'000 s'apprécie par période fiscale. CHF 320'000 par an dépasse ce seuil — chaque année constitue un délit fiscal qualifié, et les fonds en sont les produits blanchissables." },
      { s: "M. Kloser dirige une société de gestion de fortune. Il investit CHF 600'000 provenant d'une fraude commise par son propre associé dans des fonds immobiliers. M. Kloser ne peut pas être poursuivi pour blanchiment car il n'est pas l'auteur de la fraude principale.", v: false, e: "Faux : le blanchiment (art. 305bis CP) peut être commis par une personne distincte de l'auteur de l'infraction préalable. M. Kloser peut être poursuivi pour blanchiment s'il savait ou devait présumer l'origine illicite des fonds — la qualité d'auteur de l'infraction préalable n'est pas requise." }
    ]
  },
  {
    id: 3,
    titre: "Organisation de l'intermédiaire financier en matière LBA",
    description: "3 lignes de défense, FINMA enforcement, culture compliance, cas Julius Baer",
    questions: [
      // — THÉORIE (3) —
      { s: "Dans le modèle des 3 lignes de défense, le front office (RM) constitue la 1ère ligne, le compliance et le risk management la 2ème ligne, et l'audit interne la 3ème ligne.", v: true, e: "Exact : c'est le modèle standard des 3 lignes — chaque ligne a un rôle distinct dans la gestion des risques LBA." },
      { s: "La FINMA peut confisquer les bénéfices illégaux réalisés par un IF ayant violé les règles LBA.", v: true, e: "Exact : la confiscation des bénéfices illégaux est l'une des mesures d'enforcement disponibles pour la FINMA, aux côtés des injonctions et des interdictions d'exercer." },
      { s: "Les OAR (organismes d'autorégulation) exercent la surveillance LBA sur leurs membres non-bancaires sous la supervision de la FINMA.", v: true, e: "Exact : les OAR supervisent leurs membres (gestionnaires de fortune indépendants, etc.) conformément à l'art. 24 LBA, sous contrôle de la FINMA." },
      // — CAS PRATIQUES (15) —
      { s: "Dans le cas Julius Baer, la FINMA a constaté que la culture compliance était lacunaire, que les risques LBA étaient incorrectement catégorisés et que les incitations commerciales primaient sur les obligations de vigilance.", v: true, e: "Exact : la FINMA a identifié plusieurs défaillances systémiques chez Julius Baer — culture compliance insuffisante, catégorisation des risques défectueuse et incitations inopportunes." },
      { s: "Dans une banque, le RM est responsable en priorité de la qualité du dossier KYC de ses clients — le compliance ne fait que contrôler la plausibilité des informations sans se substituer au RM.", v: true, e: "Exact : art. 24 I OBA FINMA — la responsabilité primaire du KYC incombe au RM et à sa hiérarchie. Le CO exerce une responsabilité secondaire de contrôle de plausibilité." },
      { s: "Une banque dotée d'un excellent système informatique de monitoring mais dont l'équipe compliance ne traite jamais les alertes générées dispose d'une organisation LBA conforme.", v: false, e: "Faux : un système de monitoring ne suffit pas s'il n'est pas suivi d'un traitement effectif des alertes. Comme l'illustre l'affaire Banque Reyl (5'000 alertes non traitées), l'organisation doit être effective, pas seulement formelle." },
      { s: "Le CEO d'une banque qui délègue entièrement les questions compliance au CO, sans jamais s'y impliquer, peut être tenu personnellement responsable si des violations LBA systémiques sont découvertes.", v: true, e: "Exact : la responsabilité de la direction inclut la mise en place et la surveillance effective du dispositif LBA — une délégation totale sans contrôle ne suffit pas à exonérer le CEO." },
      { s: "Dans le cas Julius Baer, la FINMA a relevé que certains RM recevaient des bonus exclusivement basés sur la croissance des actifs sous gestion, sans aucune composante compliance. Ce mécanisme est incompatible avec une culture compliance saine.", v: true, e: "Exact : des incitations purement commerciales créent un conflit structurel avec les obligations LBA — la FINMA a explicitement identifié ces 'incitations inopportunes' comme facteur aggravant." },
      { s: "Une banque avec un seul CO peut avoir une organisation LBA conforme si ce CO est compétent et que les ressources sont proportionnées au profil de risque de l'établissement.", v: true, e: "Exact : il n'y a pas de seuil fixe — l'organisation doit être proportionnée au profil de risque. Un petit IF avec un CO unique peut être conforme si les ressources sont adéquates." },
      { s: "La fonction d'audit interne peut être exercée par le même département que le compliance sans créer de problème d'indépendance.", v: false, e: "Faux : l'audit interne (3ème ligne) doit être indépendant du compliance (2ème ligne) pour pouvoir contrôler efficacement ce dernier. Combiner les deux supprime cette indépendance." },
      { s: "Une banque étrangère opérant en Suisse via une succursale n'est pas soumise à la LBA suisse si son siège est dans un pays GAFI membre.", v: false, e: "Faux : toute IF opérant en Suisse est soumise à la LBA suisse, indépendamment du droit applicable au siège. L'appartenance du pays d'origine au GAFI ne crée pas d'exemption." },
      { s: "Le 'tone from the top' est concret : il se mesure notamment à l'attention que la direction accorde aux questions LBA lors des réunions, à l'allocation de ressources compliance et à l'exemplarité des dirigeants.", v: true, e: "Exact : le tone from the top n'est pas qu'un discours — il s'observe dans les décisions, les ressources allouées et le comportement des dirigeants qui donnent le ton à l'ensemble de l'organisation." },
      { s: "La FINMA peut imposer un chargé d'enquête (Untersuchungsbeauftragter) à un IF pour examiner ses pratiques LBA à ses frais.", v: true, e: "Exact : le chargé d'enquête est un outil d'enforcement de la FINMA qui peut être imposé à l'IF pour mener une investigation approfondie de ses pratiques — les coûts sont à la charge de l'IF." },
      { s: "Un IF peut valablement déléguer toutes ses obligations LBA à un prestataire externe de services compliance, ce qui le décharge de toute responsabilité.", v: false, e: "Faux : la délégation de tâches compliance à un prestataire est possible mais ne transfère pas la responsabilité légale — l'IF reste responsable du respect de ses obligations LBA et doit exercer une surveillance adéquate du prestataire." },
      { s: "Dans le cas Julius Baer, les violations LBA ont perduré sur plusieurs années notamment parce que la pression commerciale du front office dominait systématiquement les recommandations du compliance.", v: true, e: "Exact : la FINMA a constaté un déséquilibre structurel entre les intérêts commerciaux (front office) et les exigences de compliance, caractéristique d'une culture compliance lacunaire." },
      { s: "L'obligation de former les collaborateurs aux règles LBA incombe exclusivement au Compliance Officer, qui en assume seul la responsabilité.", v: false, e: "Faux : si le CO est souvent en charge de la mise en œuvre de la formation LBA, la responsabilité en revient à la direction de l'IF. La formation est une obligation institutionnelle, pas individuelle du CO." },
      { s: "Une banque dont la licence est retirée par la FINMA suite à de graves violations LBA peut également faire l'objet de poursuites pénales distinctes contre ses dirigeants.", v: true, e: "Exact : la sanction administrative (retrait de licence) et les poursuites pénales contre les personnes physiques responsables sont des procédures indépendantes qui peuvent se cumuler." },
      { s: "Dans le cas Julius Baer, la FINMA a relevé que certains dossiers de clients à haut risque étaient correctement catégorisés au départ, mais que la réévaluation périodique annuelle n'était pas systématiquement effectuée.", v: true, e: "Exact : la FINMA a constaté chez Julius Baer une catégorisation des risques parfois incorrecte ou tardive — le suivi et la réévaluation périodique des risques faisaient défaut, en violation de l'art. 19 OBA FINMA." }
    ]
  },
  {
    id: 4,
    titre: "La gestion des risques LBA (KYC)",
    description: "KYC, approche par les risques, formulaires, OBA FINMA, cas pratiques",
    questions: [
      // — THÉORIE (3) —
      { s: "L'approche fondée sur les risques signifie adapter l'intensité des diligences au niveau de risque individuel de chaque relation — et non appliquer des contrôles identiques à tous les clients.", v: true, e: "Exact : le principe fondamental du KYC LBA est la proportionnalité — les diligences sont plus légères pour les clients à faible risque et renforcées pour les relations à risques accrus." },
      { s: "L'art. 6 LBA oblige l'IF à établir l'objet et le but de la relation d'affaires lors de l'entrée en relation.", v: true, e: "Exact : art. 6 LBA — c'est la base légale du KYC initial. Comprendre pourquoi le client veut établir une relation est fondamental pour évaluer le risque LBA." },
      { s: "Le GAFI (Groupe d'Action Financière) est un organisme intergouvernemental dont les 40 recommandations constituent les standards mondiaux de lutte contre le blanchiment.", v: true, e: "Exact : le GAFI/FATF fixe les normes internationales LBA/CFT — ses recommandations servent de base aux législations nationales, dont la LBA suisse." },
      // — CAS PRATIQUES (15) —
      { s: "M. Liang, ressortissant chinois résidant à Hong Kong, souhaite ouvrir un compte dans une banque suisse pour y déposer CHF 3 millions. Il présente un passeport valide mais refuse d'expliquer l'origine de sa fortune. La banque peut ouvrir le compte sur la seule base du passeport.", v: false, e: "Faux : l'identification du cocontractant (passeport) est nécessaire mais insuffisante. La banque doit établir l'objet et le but de la relation (art. 6 LBA), l'ADE et — pour une relation à risques accrus — l'origine de la fortune. Le refus d'expliquer est lui-même un red flag." },
      { s: "Une cliente est directrice d'une ONG active dans un pays à risque GAFI. Elle reçoit régulièrement des virements de partenaires basés dans ce pays. La banque peut traiter ces opérations comme des transactions ordinaires puisque c'est une ONG caritative.", v: false, e: "Faux : les ONG actives dans des pays à risque GAFI présentent un profil de risque LBA élevé — notamment pour le financement du terrorisme. Le statut d'ONG ne crée pas d'exemption et impose au contraire des diligences renforcées." },
      { s: "Un client souhaite transférer CHF 500'000 vers un compte aux BVI sans pouvoir identifier le bénéficiaire ni expliquer la raison économique du virement. La banque doit refuser ou bloquer l'opération en attendant les clarifications.", v: true, e: "Exact : la banque ne peut pas exécuter une opération dont l'arrière-plan économique est inexpliqué. L'absence d'identification du bénéficiaire et de justification économique impose un blocage jusqu'à clarification." },
      { s: "Le formulaire A rempli à l'ouverture d'un compte est valable définitivement — il n'est pas nécessaire de le mettre à jour si l'ADE change suite à un décès ou une restructuration.", v: false, e: "Faux : le formulaire A doit être mis à jour lors de tout changement d'ADE. Les informations KYC doivent refléter la situation actuelle — l'IF a l'obligation de maintenir ses dossiers à jour (art. 7 LBA)." },
      { s: "M. Rossi est restaurateur. Il souhaite déposer CHF 70'000 en espèces correspondant aux recettes mensuelles de ses deux restaurants. Si les montants sont cohérents avec l'activité déclarée et documentée, la banque peut accepter ce dépôt.", v: true, e: "Exact : des espèces cohérentes avec une activité commerciale documentée (restauration) peuvent être acceptées. L'évaluation de la plausibilité au regard du profil du client est la démarche correcte." },
      { s: "M. Martin présente un formulaire K dans lequel il se déclare détenteur de 30% du capital d'une société cliente. La banque n'a pas besoin de vérifier davantage car 30% est inférieur au seuil de contrôle de 50%.", v: false, e: "Faux : le seuil du formulaire K est de 25% (et non 50%) de participation, ou tout contrôle effectif inférieur à ce seuil. De plus, la banque doit vérifier la cohérence et la plausibilité, pas uniquement le seuil formel." },
      { s: "La responsabilité primaire du KYC incombe au RM — le Compliance Officer exerce une responsabilité secondaire de contrôle de plausibilité des informations fournies par le RM.", v: true, e: "Exact : art. 24 I OBA FINMA — le RM est en contact direct avec le client et assume la responsabilité première de la qualité du KYC. Le CO contrôle sans se substituer au RM." },
      { s: "Un client déclare être l'ADE d'une société holding à 100%. Comme ce client est connu de la banque depuis 25 ans, aucun formulaire A formel n'est requis.", v: false, e: "Faux : les formalités CDB/KYC ne peuvent pas être contournées en raison de l'ancienneté d'une relation. Le formulaire A doit être établi lors de l'ouverture et maintenu à jour, quelle que soit la durée de la relation." },
      { s: "Un IF qui doute de la véracité des informations fournies par un client sur l'origine de sa fortune peut exiger des documents complémentaires (relevés bancaires, actes de vente, déclarations fiscales).", v: true, e: "Exact : l'IF peut et doit demander des pièces justificatives pour vérifier la plausibilité des déclarations du client. Ce droit découle directement de l'obligation de diligence raisonnable." },
      { s: "Mme Schmidt, retraitée suisse, dépose CHF 1,5 million qu'elle dit avoir hérité de son père décédé. La banque lui demande un acte de succession pour documenter l'origine des fonds. Cette demande est justifiée et normale.", v: true, e: "Exact : CHF 1,5 million est un montant significatif qui justifie une documentation de l'origine des fonds, même pour une relation à risques ordinaires. Un acte de succession est une pièce justificative raisonnable et proportionnée." },
      { s: "Un PEP étranger résidant à Zurich qui souhaite ouvrir un compte dans une banque suisse est automatiquement classé à risques accrus selon l'OBA FINMA, sans possibilité d'évaluation contraire.", v: true, e: "Exact : les PEPs étrangers sont automatiquement catégorisés à risques accrus (art. 13 al. 1 OBA FINMA), sans possibilité d'évaluation au cas par cas. Cette automaticité ne s'applique qu'aux PEPs étrangers." },
      { s: "Le Wolfsberg Group est une autorité de surveillance bancaire internationale dont les standards en matière de KYC sont obligatoires pour les banques suisses.", v: false, e: "Faux : le Wolfsberg Group est une association volontaire de grandes banques internationales qui élabore des standards de meilleures pratiques — sans pouvoir de surveillance et sans caractère obligatoire. C'est une référence de l'industrie, pas une réglementation." },
      { s: "Un client refuse de remplir le formulaire A en invoquant son droit à la protection de ses données personnelles. La banque doit accepter ce refus et ne peut pas insister.", v: false, e: "Faux : l'identification de l'ADE est une obligation légale de l'IF (art. 4 LBA). Le client n'a pas le droit de la refuser — un refus persistant doit conduire l'IF à ne pas entrer en relation ou à clôturer le compte." },
      { s: "Une société holding aux Îles Caïmans souhaite ouvrir un compte dans une banque suisse. Le bénéficiaire effectif déclaré est un citoyen suisse résidant à Genève. La banque doit identifier et vérifier cette personne en tant qu'ADE.", v: true, e: "Exact : quelle que soit la structure juridique utilisée, l'IF doit identifier la personne physique réelle qui est l'ADE des fonds. La domiciliation offshore ne modifie pas cette obligation." },
      { s: "Lors d'une révision KYC d'une relation existante, la banque découvre que l'ADE déclaré a changé trois fois en deux ans sans aucune explication. Ce comportement ne nécessite pas de clarifications particulières.", v: false, e: "Faux : des changements répétés et inexpliqués d'ADE sont un red flag LBA majeur. Ce comportement doit déclencher une clarification complémentaire approfondie et une réévaluation du risque de la relation." }
    ]
  },
  {
    id: 5,
    titre: "Gestion des risques LBA — Structures complexes",
    description: "Sociétés de domicile, art. 9a OBA FINMA, Panama Papers, diligences renforcées",
    questions: [
      // — THÉORIE (3) —
      { s: "L'art. 9a OBA FINMA, introduit lors de la révision de 2020, impose des diligences renforcées spécifiques pour les structures complexes.", v: true, e: "Exact : l'art. 9a OBA FINMA est la disposition centrale sur les structures complexes — il résulte notamment des Panama Papers (2016) et du rapport GAFI de 2016 sur la Suisse." },
      { s: "Une société de domicile est, par définition, une entité sans activité commerciale propre, servant uniquement à détenir des actifs ou à exécuter des transactions pour le compte d'un tiers.", v: true, e: "Exact : art. 4 al. 2 CDB — la société de domicile se caractérise par l'absence d'activité commerciale propre, ce qui rend l'identification de l'ADE réel particulièrement importante." },
      { s: "La complexité d'une structure est automatiquement établie dès qu'elle comprend plus de 3 entités distinctes.", v: false, e: "Faux : la complexité s'évalue qualitativement — une structure est complexe lorsque l'empilement d'entités nuit à la transparence sur l'ADE, indépendamment de tout nombre fixe d'entités." },
      // — CAS PRATIQUES (15) —
      { s: "Un client présente une structure composée de 4 sociétés holdings (Caïmans → BVI → Panama → Liechtenstein) pour ouvrir un compte. Il ne peut pas expliquer pourquoi 4 couches sont nécessaires. La banque peut accepter car tous les formulaires CDB sont signés.", v: false, e: "Faux : la signature formelle des formulaires ne suffit pas. L'art. 9a OBA FINMA impose de comprendre la raison d'être économique de la structure. L'incapacité à expliquer 4 niveaux d'entités constitue un red flag majeur justifiant le refus." },
      { s: "M. Tan est un entrepreneur singapourien. Sa société à Hong Kong détient une société aux BVI, qui détient à son tour un immeuble en Suisse. Cette structure à 3 niveaux constitue une structure complexe au sens de l'OBA FINMA.", v: true, e: "Exact : un empilement de 3 entités dans différentes juridictions rendant difficile l'identification de l'ADE correspond à la définition de la structure complexe (art. 13 al. 2 lit. h OBA FINMA)." },
      { s: "Une fondation liechtensteinoise (Stiftung) est une entité juridique sans actionnaires au registre. Cette absence d'actionnaire apparent la rend plus difficile à analyser qu'une SA en termes d'identification de l'ADE.", v: true, e: "Exact : la Stiftung n'a pas d'actionnaires — c'est précisément cette opacité structurelle qui en fait un outil potentiel de dissimulation de l'ADE, justifiant des diligences renforcées." },
      { s: "Un client explique qu'il utilise une société offshore aux BVI pour 'protéger son patrimoine contre d'éventuels créanciers suite à un litige commercial'. Cette explication peut être légitime et doit être soigneusement documentée.", v: true, e: "Exact : la protection patrimoniale contre des créanciers est un motif reconnu comme légitime. Toutefois, il doit être plausible, documenté et évalué dans le contexte global du client." },
      { s: "Les révélations des Panama Papers en avril 2016 ont directement conduit la FINMA à introduire l'art. 9a OBA FINMA lors de la révision de 2020.", v: true, e: "Exact : les Panama Papers (~215'000 sociétés offshore révélées) et le rapport GAFI de décembre 2016 ont mis en lumière les lacunes réglementaires — l'art. 9a OBA FINMA est la réponse réglementaire directe." },
      { s: "Un IF peut accepter de gérer des fonds pour une structure complexe sans en comprendre la raison économique, pourvu que le client soit de bonne réputation et présente des documents en règle.", v: false, e: "Faux : l'art. 9a OBA FINMA impose explicitement à l'IF de comprendre la raison d'être de la structure. La réputation du client et la complétude formelle des documents ne remplacent pas cette compréhension économique." },
      { s: "Pour une structure complexe, l'IF doit pouvoir identifier chaque maillon de la chaîne de contrôle jusqu'à la personne physique réelle (UBO — ultimate beneficial owner).", v: true, e: "Exact : la transparence requise exige de remonter la chaîne de contrôle jusqu'à la personne physique, en identifiant clairement chaque entité intermédiaire et son rôle." },
      { s: "M. Gomez, entrepreneur latino-américain résidant en Espagne, souhaite ouvrir un compte via une société panaméenne pour 'des raisons de confidentialité dans un contexte politique instable dans son pays d'origine'. Cette raison peut être légitime si elle est plausible et documentée.", v: true, e: "Exact : des raisons légitimes (protection dans un pays politiquement instable) peuvent justifier une structure offshore. L'IF doit cependant évaluer la plausibilité de cette justification et la documenter soigneusement." },
      { s: "L'art. 9a OBA FINMA interdit aux banques suisses d'entrer en relation avec des structures complexes.", v: false, e: "Faux : l'art. 9a OBA FINMA n'interdit pas les structures complexes — il impose des diligences renforcées : comprendre la raison d'être, identifier tous les maillons jusqu'à l'UBO, et documenter l'analyse." },
      { s: "Lors des Panama Papers, les journalistes de l'ICIJ ont publié des données sur environ 215'000 sociétés offshore liées à des utilisations parfois illicites (évasion fiscale, corruption, blanchiment).", v: true, e: "Exact : l'ICIJ a publié en avril 2016 des données sur ~215'000 sociétés offshore issues du cabinet Mossack Fonseca, mettant en lumière leurs utilisations à des fins parfois illicites." },
      { s: "Si un IF ne comprend pas la raison d'être d'une structure complexe présentée par un client, il peut tout de même l'accepter à condition que le formulaire A soit dûment rempli et signé.", v: false, e: "Faux : l'incompréhension de la raison d'être d'une structure est rédhibitoire selon l'art. 9a OBA FINMA. Un formulaire A signé ne remplace pas la compréhension économique de la structure — sans cette compréhension, la relation ne doit pas être acceptée." },
      { s: "Une société offshore peut avoir des objectifs commerciaux légitimes (opérations internationales, planification successorale) — c'est l'opacité sans justification qui crée le risque LBA, pas la domiciliation offshore en soi.", v: true, e: "Exact : une société offshore n'est pas illicite en soi. Le risque LBA naît de l'opacité et de l'absence de justification économique — pas simplement du lieu de domiciliation." },
      { s: "Dans le cas pratique du module 5, la banque avait accepté une structure complexe sans pouvoir expliquer la raison d'être de chaque entité. La FINMA lui a reproché ce manque de diligence.", v: true, e: "Exact : l'absence de compréhension de la raison d'être de chaque maillon d'une structure complexe constitue une violation de l'art. 9a OBA FINMA — la FINMA attend une documentation claire de la justification économique." },
      { s: "Pour satisfaire aux exigences de l'art. 9a OBA FINMA sur les structures complexes, il suffit à l'IF d'obtenir un organigramme de la structure, sans nécessité de comprendre la logique économique sous-jacente.", v: false, e: "Faux : l'organigramme est un élément nécessaire mais insuffisant. L'art. 9a OBA FINMA impose également de comprendre la raison d'être économique de chaque entité — un organigramme incompris ne remplit pas l'obligation." },
      { s: "Mme Dubois souhaite ouvrir un compte pour une fondation familiale aux Bahamas dont elle est l'administratrice. Elle affirme que la fondation sert à gérer l'héritage de son père. La banque doit évaluer la plausibilité de cette explication et documenter la raison d'être de la structure avant d'accepter.", v: true, e: "Exact : une fondation familiale offshore est une structure complexe au sens de l'OBA FINMA. Même si l'explication (héritage) est légitime en apparence, l'IF doit évaluer la plausibilité, identifier tous les acteurs (administrateur, bénéficiaires) et documenter la raison d'être de la structure." }
    ]
  },
  {
    id: 6,
    titre: "Analyse du risque LBA de la relation d'affaires",
    description: "Clarifications complémentaires, position de garant, analyse holistique, décisions pratiques",
    questions: [
      // — THÉORIE (3) —
      { s: "La clarification complémentaire (art. 15 OBA FINMA) est déclenchée par des indices de soupçon et vise à comprendre l'arrière-plan économique d'une relation ou transaction paraissant suspecte.", v: true, e: "Exact : la clarification complémentaire est l'investigation approfondie menée lorsque des éléments rendent l'arrière-plan économique d'une opération ou relation suspect." },
      { s: "La documentation des analyses LBA est obligatoire uniquement lorsque le soupçon est confirmé et qu'une communication au MROS est effectuée.", v: false, e: "Faux : la documentation est toujours obligatoire, même si le soupçon est finalement écarté. Elle doit permettre de démontrer a posteriori que les diligences ont bien été effectuées et que la décision de ne pas communiquer était fondée." },
      { s: "La 'position de garant' (Garantenstellung) du CO signifie qu'il a l'obligation légale d'agir pour prévenir ou signaler des infractions LBA dont il a connaissance.", v: true, e: "Exact : la Garantenstellung impose au CO d'agir — son inaction délibérée face à des violations connues peut engager sa responsabilité pénale (art. 305bis/ter CP)." },
      // — CAS PRATIQUES (15) —
      { s: "Une analyste LBA reçoit une alerte sur un client qui a viré CHF 500'000 vers un compte en Russie. Elle effectue une recherche Google de 5 minutes, ne trouve rien, et classe l'alerte. Cette approche est suffisante.", v: false, e: "Faux : une recherche Google de 5 minutes ne constitue pas une clarification complémentaire sérieuse. Une analyse sérieuse implique la consultation de bases de données spécialisées (World-Check), l'examen du profil complet du client et une documentation détaillée." },
      { s: "Un client PEP explique que sa fortune de CHF 15 millions provient de 'ses activités de business'. Cette explication vague est insuffisante pour documenter l'origine de la fortune d'un PEP à risques accrus.", v: true, e: "Exact : pour un PEP à risques accrus, l'origine de la fortune doit être établie de manière convaincante et documentée. Une déclaration vague et non étayée ne satisfait pas à cette exigence." },
      { s: "M. Rossi, gérant de fortune indépendant, reçoit une explication orale de son client pour justifier une transaction inhabituelle. Le client déclare que 'c'est une affaire personnelle'. M. Rossi peut clore le dossier sur cette base.", v: false, e: "Faux : une explication orale vague ('c'est personnel') ne constitue pas une clarification suffisante. M. Rossi doit obtenir des explications vérifiables et documentées — l'inaction peut engager sa responsabilité au titre de l'art. 305ter CP." },
      { s: "L'analyse 'ponctuelle' consiste à examiner une transaction isolée dans son contexte global, en tenant compte du profil complet du client et de l'historique de la relation.", v: false, e: "Faux : c'est l'analyse 'holistique' qui examine une situation dans son contexte global. L'analyse 'ponctuelle' porte sur un événement ou une transaction spécifique de manière isolée, sans nécessairement prendre en compte l'ensemble de la relation." },
      { s: "Si après des clarifications approfondies le soupçon demeure non dissipé, l'IF doit communiquer au MROS (art. 9 LBA). Il peut également envisager de rompre la relation d'affaires.", v: true, e: "Exact : l'IF ne peut pas 'laisser courir' une relation suspecte. L'obligation de communiquer au MROS est déclenchée dès que le soupçon est fondé et que les clarifications ne l'ont pas dissipé. La rupture de la relation peut aussi s'ensuivre." },
      { s: "Un rapport LBA annuel pour une relation à risques accrus doit décrire les activités du compte, évaluer leur cohérence avec le profil du client et conclure sur l'opportunité de maintenir ou non la relation.", v: true, e: "Exact : le rapport LBA annuel est un outil structuré d'évaluation de la relation — il documente la revue périodique obligatoire pour les relations à risques accrus (art. 19 OBA FINMA)." },
      { s: "Une analyste LBA découvre un article de presse récent signalant qu'un client est impliqué dans une enquête judiciaire en Italie pour corruption. Elle n'a pas à en tenir compte car le client a un profil de risque ordinaire chez la banque.", v: false, e: "Faux : un article de presse négatif est un facteur déclencheur de clarification complémentaire, indépendamment du profil de risque initial du client. L'IF doit réévaluer le risque et décider des actions appropriées." },
      { s: "Un RM qui reçoit une explication plausible du client pour une transaction inhabituelle peut clore la clarification sans la documenter par écrit.", v: false, e: "Faux : toute clarification, quelle qu'en soit la conclusion, doit être documentée par écrit. La documentation est précisément là pour prouver que la plausibilité a été vérifiée — une clarification non documentée est comme si elle n'avait pas eu lieu." },
      { s: "Transparency International publie l'Indice de Perception de la Corruption (CPI) — un score bas (proche de 0) indique un niveau de corruption élevé dans ce pays, ce qui augmente le risque LBA des relations avec des contreparties de ce pays.", v: true, e: "Exact : le CPI de Transparency International est un indicateur de référence pour évaluer le risque pays en matière de corruption. Un score bas (corruption élevée) justifie des diligences renforcées." },
      { s: "La qualité d'une information utilisée dans une clarification LBA s'évalue notamment selon son ancienneté, la fiabilité de sa source et sa convergence avec d'autres sources indépendantes.", v: true, e: "Exact : le 'traitement de l'information' LBA s'évalue selon plusieurs dimensions : ancienneté (une information vieille est moins fiable), source (officielle > presse > client lui-même) et convergence (plusieurs sources indépendantes renforcent la fiabilité)." },
      { s: "Lors d'une analyse d'une relation à risques accrus, l'IF peut se limiter aux informations fournies par le client lui-même sans recourir à des bases de données externes ou des recherches indépendantes.", v: false, e: "Faux : pour une relation à risques accrus, les informations du client doivent être complétées par des recherches indépendantes (World-Check, Lexis Nexis, presse, bases de données officielles) — se fier uniquement au client ne satisfait pas l'obligation de diligence renforcée." },
      { s: "Un IF qui reçoit une demande de renseignements d'une autorité suisse de poursuite pénale concernant un client doit y répondre, même si cela implique de lever le secret bancaire dans le cadre légal prévu.", v: true, e: "Exact : le secret bancaire suisse n'est pas absolu — il cède face aux demandes d'entraide judiciaire légalement fondées des autorités suisses de poursuite pénale." },
      { s: "Le rapport de monitoring LBA FINMA 2025 souligne que la tolérance au risque LBA doit être clairement définie par les organes dirigeants pour que le dispositif compliance soit efficace.", v: true, e: "Exact : le rapport FINMA du 17 novembre 2025 souligne que l'efficacité du dispositif LBA présuppose une tolérance au risque clairement définie et communiquée par la haute direction — pas seulement des procédures techniques." },
      { s: "Identifier les 'éléments manquants' dans un dossier KYC signifie uniquement recenser les cases vides dans les formulaires d'ouverture de compte.", v: false, e: "Faux : identifier les éléments manquants signifie déterminer quelles informations font défaut pour avoir une image complète du client et évaluer correctement son risque LBA — c'est une analyse de substance, pas une vérification formelle de cases cochées." },
      { s: "Un analyste LBA reçoit une alerte sur une cliente dont le compte reçoit soudainement CHF 1,2 million en provenance d'une banque au Kazakhstan. La cliente est une retraitée suisse sans activité internationale déclarée. Ce virement doit déclencher une clarification complémentaire immédiate.", v: true, e: "Exact : un virement de CHF 1,2 million depuis le Kazakhstan sur le compte d'une retraitée sans activité internationale est manifestement incohérent avec son profil — c'est un facteur déclencheur de clarification complémentaire (art. 15 OBA FINMA) typique." }
    ]
  },
  {
    id: 7,
    titre: "Surveillance des transactions",
    description: "Monitoring, alertes, typologies, affaire Banque Reyl, décisions pratiques",
    questions: [
      // — THÉORIE (3) —
      { s: "Les art. 6 et 7 LBA imposent aux IF de surveiller les opérations pour détecter celles qui paraissent inhabituelles au regard du profil du client.", v: true, e: "Exact : ces articles constituent les bases légales de l'obligation de monitoring. L'art. 7 LBA précise l'obligation d'examiner les transactions inhabituelles et de clarifier leur arrière-plan économique." },
      { s: "Une transaction 'atypique' déclenche directement l'obligation de communiquer au MROS.", v: false, e: "Faux : une transaction 'atypique' (inhabituelle) déclenche une analyse complémentaire, pas automatiquement une communication au MROS. C'est seulement si cette analyse révèle un soupçon fondé que l'obligation de communiquer (art. 9 LBA) est déclenchée." },
      { s: "La documentation des analyses de transactions est obligatoire même lorsque la conclusion est l'absence de soupçon.", v: true, e: "Exact : art. 22 OBA FINMA — la documentation consigne l'alerte, l'analyse effectuée, les sources consultées et la décision prise. Elle doit être conservée même quand le soupçon est écarté." },
      // — CAS PRATIQUES (15) —
      { s: "Dans l'affaire Banque Reyl (2025), la FINMA a constaté l'accumulation de 5'000 alertes de transactions non traitées depuis plus de 2 mois, ainsi que des centaines de millions liés à des PEPs d'Asie centrale qui auraient transité sans déclenchement de communication MROS.", v: true, e: "Exact : l'affaire Banque Reyl illustre une double violation grave — accumulation massive d'alertes non traitées (violation de l'obligation de surveillance) et absence de communication MROS pour des fonds liés à des PEPs (violation de l'art. 9 LBA)." },
      { s: "Un système de monitoring automatisé génère 200 alertes par jour. L'équipe LBA ne peut en traiter que 50. Il est acceptable de laisser les 150 alertes non traitées s'accumuler faute de ressources.", v: false, e: "Faux : l'accumulation d'alertes non traitées est une violation grave de l'obligation de surveillance (comme l'illustre Banque Reyl). Si les ressources sont insuffisantes, l'IF doit les renforcer — il ne peut pas invoquer un manque de ressources pour justifier le non-traitement d'alertes." },
      { s: "M. Chen effectue 10 virements de CHF 24'500 vers des comptes différents en 5 jours, en indiquant comme motif 'paiements fournisseurs'. Ces montants légèrement inférieurs à CHF 25'000 (seuil d'alerte fréquent) présentent des caractéristiques de structuring.", v: true, e: "Exact : le structuring (smurfing) consiste précisément à fractionner des transactions pour rester sous les seuils d'alerte. Ce schéma de 10 paiements quasi-identiques légèrement sous seuil est un red flag classique." },
      { s: "Un client effectue habituellement des retraits en espèces de CHF 500-1'000 par semaine. Ce mois, il effectue 6 retraits de CHF 9'800 en 12 jours. Ce comportement déviant de son profil habituel doit déclencher une analyse.", v: true, e: "Exact : le changement brutal de comportement transactionnel (retrait de 6× le montant habituel en fractionnement systématique) est un signal d'alerte classique justifiant une analyse complémentaire." },
      { s: "Une alerte de transaction monitoring est transmise directement et automatiquement au MROS par le système informatique de la banque.", v: false, e: "Faux : le système de monitoring génère des alertes qui doivent être examinées par des analystes LBA qualifiés. Ce n'est qu'après analyse humaine, si un soupçon fondé est confirmé, que l'obligation de communication au MROS (art. 9 LBA) est déclenchée." },
      { s: "Un client explique qu'il a reçu CHF 2 millions d'un ami à titre de prêt privé, sans contrat écrit ni documentation. Cette explication verbale suffit pour clore l'analyse de la transaction.", v: false, e: "Faux : un prêt privé de CHF 2 millions sans contrat écrit est une explication insuffisante. L'IF doit obtenir une documentation probante (contrat de prêt, identité du prêteur, justification économique) pour vérifier la plausibilité." },
      { s: "Un IF détecte une transaction de CHF 150'000 vers un compte en Iran (pays sous sanctions SECO/ONU). L'IF doit bloquer ce virement et prendre contact avec les autorités compétentes, quel que soit le motif invoqué.", v: true, e: "Exact : les sanctions SECO/ONU imposent le blocage immédiat de toute transaction impliquant des pays ou entités sanctionnés. Iran est sous sanctions — aucune exception commerciale ne permet l'exécution sans autorisation des autorités compétentes." },
      { s: "Un RM certifie à l'analyste LBA que 'tout est en ordre' pour une transaction suspecte, sans fournir de documentation. L'analyste LBA peut clore l'alerte sur la base de cette certification.", v: false, e: "Faux : la certification d'un RM sans documentation ne constitue pas une clarification suffisante. L'analyste LBA doit obtenir des éléments probants et documentés — une assurance verbale d'un RM ne suffit pas et peut même créer une suspicion supplémentaire." },
      { s: "M. Garcia est un homme d'affaires dont le profil KYC mentionne des activités à Panama. Il effectue un virement de CHF 800'000 vers Panama. L'analyste LBA doit vérifier que ce montant est cohérent avec l'ampleur des activités documentées, même si la destination correspond au profil.", v: true, e: "Exact : une transaction doit être cohérente non seulement quant à la destination mais aussi quant au montant. Un virement de CHF 800'000 doit être vérifié par rapport à l'ampleur des activités déclarées — même si Panama est mentionné dans le profil." },
      { s: "Un analyste LBA identifie une transaction qu'il juge suspecte mais décide de ne pas la signaler, craignant de perturber une relation commerciale importante de la banque. Cette décision constitue une violation grave de ses obligations légales.", v: true, e: "Exact : aucune considération commerciale ne peut prévaloir sur l'obligation légale de communication au MROS (art. 9 LBA). Un analyste qui supprime délibérément une alerte pour des raisons commerciales commet une violation grave." },
      { s: "Les typologies de blanchiment publiées chaque année par le MROS dans son rapport annuel servent notamment à calibrer les scénarios de détection dans les systèmes de monitoring automatisé.", v: true, e: "Exact : les typologies décrivent des schémas de blanchiment connus et récurrents — elles permettent aux IF d'affiner leurs règles de détection et de former leurs analystes à reconnaître ces patterns." },
      { s: "Dans l'affaire Banque Reyl (2025), la FINMA n'a pas prononcé de mesures significatives car il s'agissait de la première infraction constatée et les violations étaient de nature administrative.", v: false, e: "Faux : la FINMA a prononcé des mesures significatives contre Banque Reyl — l'accumulation de 5'000 alertes non traitées et les montants liés à des PEPs constituent des violations graves de la LBA, pas des infractions mineures." },
      { s: "Le 'monitoring comportemental' compare les transactions actuelles d'un client avec son profil habituel et son historique pour détecter des comportements anormaux — une déviance significative déclenche une alerte.", v: true, e: "Exact : le monitoring comportemental (ou profilage transactionnel) est un outil clé de détection — il identifie les transactions qui dévient statistiquement du comportement normal du client." },
      { s: "Un IF peut désactiver temporairement les règles de monitoring pour un client VIP afin de réduire le nombre d'alertes qui perturbent la relation commerciale.", v: false, e: "Faux : désactiver ou contourner les règles de monitoring pour des clients VIP est une violation grave de l'obligation de surveillance (art. 6-7 LBA). Le statut de client VIP ne crée aucune exemption — il peut même justifier une surveillance accrue." },
      { s: "Dans une banque, l'analyste LBA qui traite une alerte doit documenter : l'alerte elle-même, les sources consultées pour l'analyser, sa conclusion et la décision prise — même si la conclusion est l'absence de soupçon.", v: true, e: "Exact : art. 22 OBA FINMA — la documentation complète du traitement de chaque alerte est obligatoire. Elle constitue la preuve que l'IF a rempli ses obligations de surveillance, quel que soit le résultat de l'analyse." }
    ]
  },
  {
    id: 8,
    titre: "PEPs et risques de corruption",
    description: "PEPs, LVP, source of wealth, corruption, diligence renforcée, cas pratiques",
    questions: [
      // — THÉORIE (3) —
      { s: "Les PEPs étrangers sont automatiquement qualifiés à risques accrus selon l'OBA FINMA — sans possibilité d'évaluation contraire.", v: true, e: "Exact : les PEPs étrangers sont automatiquement catégorisés à risques accrus (art. 13 al. 1 OBA FINMA). Cette automaticité ne vaut que pour les PEPs étrangers — les PEPs suisses et d'organisations internationales permettent une évaluation au cas par cas." },
      { s: "La LVP (RS 196.1) permet à la Suisse de bloquer et restituer les avoirs illicites de PEPs étrangers même sans demande d'entraide judiciaire formelle de l'État d'origine.", v: true, e: "Exact : la LVP est un instrument autonome permettant à la Suisse d'agir unilatéralement pour bloquer et restituer les avoirs de potentats étrangers — notamment lorsque l'État d'origine est défaillant ou compromis." },
      { s: "La corruption passive désigne le fait de donner un pot-de-vin à un agent public — la corruption active désigne le fait d'en recevoir un.", v: false, e: "Faux : c'est l'inverse. La corruption passive = recevoir un avantage (corruptibilité du fonctionnaire). La corruption active = donner l'avantage (le corrupteur). Un fonctionnaire convaincu de corruption passive reçoit des pots-de-vin." },
      // — CAS PRATIQUES (15) —
      { s: "M. Ndiaye se présente à une banque suisse souhaitant déposer CHF 10 millions. Il est ministre des Finances en exercice d'un pays d'Afrique de l'Ouest. La banque doit classifier cette relation comme à risques accrus et obtenir une approbation de la direction avant d'entrer en relation.", v: true, e: "Exact : M. Ndiaye est un PEP étranger → risques accrus automatiques. Art. 19 al. 1 OBA FINMA : l'entrée en relation avec un PEP étranger nécessite l'approbation de la direction (senior management)." },
      { s: "Mme Petrova est l'épouse d'un gouverneur régional russe. Elle souhaite ouvrir un compte personnel en Suisse. Elle n'est pas elle-même PEP et doit être traitée comme une cliente ordinaire.", v: false, e: "Faux : l'OBA FINMA étend le régime PEP aux proches des PEPs (conjoint/partenaire, enfants, parents, personnes notoirement proches). Mme Petrova, épouse d'un gouverneur, est couverte par ce régime et doit être traitée avec des diligences renforcées." },
      { s: "Un ancien Premier ministre a quitté ses fonctions il y a 4 mois. Il souhaite ouvrir un compte dans une banque suisse. La banque peut le traiter immédiatement comme un client ordinaire puisqu'il n'est plus en fonction.", v: false, e: "Faux : un ex-PEP reste sous surveillance accrue pendant une période de transition (généralement 1 à 5 ans selon les établissements) — son influence, ses réseaux et ses actifs acquis persistent bien au-delà de la fin de sa fonction." },
      { s: "Un client se présente comme 'investisseur international' avec une fortune de CHF 40 millions 'provenant du business en Afrique'. Il est fils du Président d'un pays africain. La banque doit traiter ce dossier avec des diligences renforcées.", v: true, e: "Exact : le fils d'un chef d'État est un proche de PEP étranger → diligences renforcées obligatoires. De plus, la fortune de CHF 40 millions d'un 'investisseur' lié à un chef d'État africain nécessite une documentation convaincante de la source of wealth." },
      { s: "La 'source of wealth' d'un PEP dont la fortune déclarée (CHF 30 millions) est manifestement disproportionnée par rapport à ses revenus officiels (CHF 90'000/an de salaire de fonctionnaire) constitue un red flag LBA majeur.", v: true, e: "Exact : une incohérence flagrante entre le patrimoine et les revenus officiels est un indicateur classique de corruption — la source of wealth doit expliquer de manière convaincante comment le PEP a légalement constitué un tel patrimoine." },
      { s: "M. Beaumont est conseiller communal dans une ville suisse de taille moyenne. Il doit être automatiquement classé PEP à risques accrus, comme tout PEP étranger.", v: false, e: "Faux : pour les PEPs suisses, une évaluation au cas par cas est possible (art. 13 al. 2 OBA FINMA). Un conseiller communal d'une ville de taille moyenne peut être évalué différemment d'un Conseiller fédéral ou d'un directeur de grande institution." },
      { s: "Un banquier genevois perçoit CHF 200'000 d'un PEP étranger pour 'faciliter et accélérer' l'ouverture d'un compte dans sa banque. Ce paiement peut caractériser un acte de corruption active.", v: true, e: "Exact : recevoir un paiement pour 'faciliter' un acte administratif est une forme de corruption. Le banquier qui reçoit cette somme commet potentiellement un acte de corruption active et peut être impliqué dans le blanchiment des fonds du PEP." },
      { s: "La Wolfsberg Guidance on PEPs (2017) est contraignante pour les banques suisses au même titre que l'OBA FINMA.", v: false, e: "Faux : la Wolfsberg Guidance est un document de meilleures pratiques publié par le Wolfsberg Group (association de grandes banques) — sans force légale contraignante. L'OBA FINMA est la source légale — la Wolfsberg Guidance est une référence complémentaire." },
      { s: "Une banque suisse qui gère des fonds d'un potentat étranger déchu peut être tenue de bloquer ces avoirs en application de la LVP, même si aucune demande d'entraide judiciaire n'a été transmise par l'État d'origine.", v: true, e: "Exact : la LVP est un instrument autonome permettant à la Suisse d'agir sans attendre une demande d'entraide — particulièrement utile lorsque l'État d'origine est lui-même compromis ou défaillant." },
      { s: "La décision d'entrer en relation d'affaires avec un PEP étranger doit être approuvée par la direction (senior management) de l'IF, selon l'art. 19 al. 1 OBA FINMA.", v: true, e: "Exact : pour les PEPs étrangers (automatiquement à risques accrus), l'entrée en relation nécessite une décision explicite de la direction — pas seulement du RM ou du compliance." },
      { s: "M. Santos est un homme d'affaires brésilien dont le frère est sénateur au Brésil. M. Santos n'est pas lui-même PEP et doit être évalué comme client ordinaire sans considération de la situation de son frère.", v: false, e: "Faux : les membres de la famille proche d'un PEP (dont les frères et sœurs, selon les politiques internes et les standards du Wolfsberg Group) peuvent être soumis à des diligences renforcées. L'OBA FINMA couvre les 'personnes notoirement proches' d'un PEP." },
      { s: "Un PEP étranger bien connu du public, dont la fortune est régulièrement mentionnée dans la presse économique, n'a pas besoin de documenter l'origine de sa fortune auprès de sa banque suisse.", v: false, e: "Faux : la notoriété publique ne dispense pas de l'obligation de documentation de la source of wealth. Un PEP 'connu' peut précisément avoir bâti sa fortune via des mécanismes illicites — c'est pourquoi la documentation reste obligatoire." },
      { s: "Les Egmont Group indicators for corruption sont des indicateurs pratiques (red flags) publiés par le réseau international de cellules FIU pour aider les IF à identifier les fonds liés à la corruption.", v: true, e: "Exact : le Groupe Egmont (160+ cellules FIU dans le monde, dont le MROS) publie des typologies et indicateurs pratiques sur la corruption — ces outils aident les IF à calibrer leur monitoring et leurs clarifications." },
      { s: "M. Osei est directeur général d'une entreprise publique ghanéenne. Son épouse souhaite ouvrir un compte privé en Suisse pour y déposer CHF 2 millions. La banque peut traiter Mme Osei comme une cliente ordinaire car elle n'exerce elle-même aucune fonction publique.", v: false, e: "Faux : Mme Osei est l'épouse d'un dirigeant d'entreprise publique — elle est couverte par le régime PEP comme proche d'un PEP étranger. La banque doit appliquer des diligences renforcées, notamment documenter la source of wealth des CHF 2 millions." },
      { s: "Lors de l'examen annuel d'une relation PEP à risques accrus, la banque constate que le client a récemment fait l'objet d'articles de presse négatifs dans son pays d'origine (accusations de corruption). La banque peut maintenir la relation sans modification du niveau de risque si aucune condamnation pénale n'a encore été prononcée.", v: false, e: "Faux : des allégations publiques de corruption constituent un facteur déclencheur de clarification complémentaire et de réévaluation du profil de risque — l'absence de condamnation ne suffit pas à ignorer ces informations. La banque doit réévaluer le risque et documenter sa décision." }
    ]
  },
  {
    id: 9,
    titre: "La Convention de Diligence des Banques (CDB 20)",
    description: "Formulaires CDB, trusts, identification de l'ADE, cas pratiques CDB",
    questions: [
      // — THÉORIE (3) —
      { s: "La CDB est une convention de droit privé entre les banques membres de l'ASB — elle n'a pas la force d'une loi fédérale mais s'impose contractuellement à ses signataires.", v: true, e: "Exact : la CDB est une autodiscipline contractuelle de l'Association suisse des banquiers — distincte de la LBA (loi fédérale) et de l'OBA FINMA (ordonnance). Les deux niveaux coexistent et se complètent." },
      { s: "Le Formulaire T est le formulaire CDB spécifiquement conçu pour identifier les acteurs d'un trust (settlor, trustee, protector, bénéficiaires).", v: true, e: "Exact : le Formulaire T remplace le Formulaire A pour les trusts — il identifie chaque acteur de la structure et permet à la banque de comprendre qui sont les parties impliquées." },
      { s: "Le Formulaire S s'applique aux sociétés cotées sur une bourse reconnue et les dispense de l'obligation d'identifier l'ADE.", v: true, e: "Exact : les sociétés cotées sur une bourse reconnue sont exemptées de l'identification de l'ADE car elles sont soumises à des obligations de transparence publique (art. 4 al. 1 CDB)." },
      // — CAS PRATIQUES (15) —
      { s: "Cas pratique IBICO HOLDING SA — L'ADE (John Smith) n'a jamais été rencontré personnellement par la banque. Les documents ont été remis par un avocat genevois mandaté. Cette situation est problématique car la banque ne peut pas valider directement l'identité et les déclarations de l'ADE.", v: true, e: "Exact : la CDB exige une identification directe et fiable du cocontractant et de l'ADE. La remise de documents par un tiers (même un avocat réputé) sans rencontre directe de l'ADE crée une incertitude sur la fiabilité des informations." },
      { s: "Un client souhaite ouvrir un compte pour un trust dont il est à la fois settlor et bénéficiaire. Comme il s'agit de la même personne, la banque n'a pas besoin de formulaire spécifique.", v: false, e: "Faux : même lorsque le settlor et le bénéficiaire sont la même personne, le Formulaire T doit être utilisé pour les trusts. La structure juridique du trust nécessite toujours une documentation spécifique de chaque rôle." },
      { s: "M. Ito est directeur d'une société japonaise cotée à la Bourse de Tokyo. La banque peut utiliser le Formulaire S et n'est pas tenue d'identifier l'ADE de la société.", v: true, e: "Exact : une société cotée sur une bourse reconnue (dont Tokyo Stock Exchange) bénéficie de l'exemption CDB via le Formulaire S — la transparence publique imposée aux sociétés cotées justifie cette exemption." },
      { s: "Une banque genevoise accepte un formulaire A signé par un avocat au nom de son client absent. Cette procédure est conforme à la CDB tant que l'avocat est réputé.", v: false, e: "Faux : comme illustré par le cas IBICO, la remise de documents via un tiers sans rencontre directe de l'ADE est problématique. La CDB impose une identification fiable — la réputation de l'avocat ne remplace pas la vérification directe." },
      { s: "Dans un trust discrétionnaire, le trustee dispose d'un pouvoir d'appréciation pour décider des distributions aux bénéficiaires — la liste des bénéficiaires peut être ouverte et évoluer dans le temps.", v: true, e: "Exact : le trust discrétionnaire se caractérise précisément par cette discrétion du trustee. La liste des bénéficiaires potentiels peut être ouverte, ce qui complique l'identification KYC par rapport à un trust fixe." },
      { s: "Le protector d'un trust peut disposer d'un droit de veto sur les décisions du trustee ou du pouvoir de le remplacer, selon les termes du deed of trust.", v: true, e: "Exact : le protector (ou curator) est un acteur facultatif du trust qui exerce une surveillance sur le trustee. Ses pouvoirs exacts sont définis dans le deed of trust — veto, remplacement du trustee, etc." },
      { s: "Une banque zurichoise ouvre un compte pour une fondation liechtensteinoise (Stiftung) dont l'ADE déclaré est un citoyen kazakh. La banque doit utiliser le Formulaire T et vérifier l'identité de cet ADE ainsi que la plausibilité de la structure.", v: false, e: "Faux : le Formulaire T est pour les trusts. Pour une fondation (Stiftung), qui est une structure distincte, d'autres formulaires et diligences s'appliquent (analyse de la structure complexe, formulaire A pour l'ADE). La fondation ne se traite pas comme un trust." },
      { s: "Une société offshore dont l'actionnaire unique est une autre société offshore doit être identifiée en remontant la chaîne de participation jusqu'à la personne physique réelle (UBO).", v: true, e: "Exact : l'obligation CDB/KYC est d'identifier la personne physique réelle qui contrôle en dernière instance les valeurs patrimoniales — l'empilement de sociétés ne peut pas servir d'écran définitif." },
      { s: "Un client déclare être l'ADE d'une société holding à 100%. Comme ce client est connu de la banque depuis 20 ans, aucun formulaire A n'est formellement requis.", v: false, e: "Faux : les formalités CDB (dont le Formulaire A) doivent être remplies quelle que soit l'ancienneté de la relation. Une longue relation ne dispense pas des obligations formelles d'identification de l'ADE." },
      { s: "Le deed of trust est l'acte constitutif du trust qui fixe notamment l'identité du settlor, les obligations du trustee, les droits des bénéficiaires et les pouvoirs du protector.", v: true, e: "Exact : le deed of trust est le document fondateur du trust — il définit la structure juridique, les parties, les règles de distribution et les mécanismes de gouvernance." },
      { s: "La CDB 20 impose l'identification du cocontractant uniquement pour les ouvertures de compte bancaire, et non pour les transactions ponctuelles importantes.", v: false, e: "Faux : la CDB impose l'identification lors de toute relation d'affaires durable. Pour les transactions ponctuelles (sans relation d'affaires), la LBA fixe des seuils à partir desquels l'identification s'impose (art. 3 LBA)." },
      { s: "Dans le cas pratique CDB (module 9), la banque avait géré des fonds d'un trust sans connaître l'identité des bénéficiaires finaux. Cette lacune constitue une violation des obligations d'identification de la CDB.", v: true, e: "Exact : connaître les bénéficiaires d'un trust est une exigence fondamentale de la CDB (Formulaire T). Gérer des fonds sans identifier les bénéficiaires expose l'IF à une violation des obligations CDB et KYC." },
      { s: "La CDB 20 (en vigueur depuis 2020) a renforcé les exigences d'identification des ADE en alignant ses standards sur l'OBA FINMA 2020 et les recommandations GAFI.", v: true, e: "Exact : la révision CDB 20 a harmonisé ses exigences avec le renforcement réglementaire de l'OBA FINMA 2020 — notamment sur les structures complexes et l'identification des ADE." },
      { s: "Le Formulaire I est utilisé dans les situations où le cocontractant est un intermédiaire financier qui atteste agir pour son propre compte.", v: true, e: "Exact : le Formulaire I est utilisé dans des situations spécifiques où le cocontractant est lui-même un intermédiaire financier soumis à des obligations de diligence équivalentes et qui atteste agir pour son propre compte." },
      { s: "Dans le cas pratique IBICO HOLDING SA, si la banque avait exigé une rencontre en face à face avec John Smith (l'ADE déclaré) avant d'ouvrir le compte, elle aurait pu valider directement l'identité et les déclarations du bénéficiaire effectif, réduisant ainsi le risque de KYC défaillant.", v: true, e: "Exact : la rencontre directe avec l'ADE est la meilleure pratique — elle permet de valider l'identité, d'évaluer la cohérence des déclarations et de déceler d'éventuelles incohérences que la remise de documents via un tiers ne permet pas de détecter." }
    ]
  },
  {
    id: 10,
    titre: "La communication au MROS",
    description: "Art. 9/10/11 LBA, blocage des fonds, cas Victor Hugo, obligations pratiques",
    questions: [
      // — THÉORIE (3) —
      { s: "L'art. 9 LBA crée une obligation absolue de communiquer au MROS lorsque l'IF sait ou présume que des fonds sont liés à un crime ou au financement du terrorisme.", v: true, e: "Exact : l'art. 9 LBA est une obligation — pas une faculté. Dès que l'IF 'sait ou présume' (dol éventuel suffisant), il doit communiquer sans délai au MROS." },
      { s: "L'art. 11 LBA protège l'IF qui communique de bonne foi au MROS contre toute action civile ou pénale, même si la communication s'avère non fondée a posteriori.", v: true, e: "Exact : la protection de l'art. 11 LBA est civile ET pénale, et s'applique dès lors que la communication a été faite de bonne foi — indépendamment du résultat de l'enquête qui s'ensuit." },
      { s: "Après une communication au MROS, le blocage des fonds prévu par l'art. 10 LBA dure 5 jours ouvrables, délai pendant lequel le MROS analyse la communication.", v: true, e: "Exact : art. 10 al. 4 LBA — le blocage dure 5 jours ouvrables. Si le MROS transmet aux autorités pénales, le gel peut être prolongé par les autorités pénales compétentes." },
      // — CAS PRATIQUES (15) —
      { s: "Cas Victor Hugo — Shiva (RM) découvre qu'Azim, déléguée de Rakhmat, est fille du Président du Kirghizistan. Shiva doit immédiatement communiquer au MROS sans effectuer d'autres clarifications préalables.", v: false, e: "Faux : la découverte du lien PEP déclenche une procédure de clarification renforcée, pas une communication immédiate au MROS. L'IF doit d'abord clarifier l'arrière-plan, évaluer le risque, et communiquer au MROS seulement si le soupçon est fondé après analyse." },
      { s: "Cas Victor Hugo — Rakhmat est cliente de la banque depuis 15 ans avec un profil ordinaire. La découverte qu'elle est liée à un PEP étranger (Azim, fille du Président du Kirghizistan) transforme cette relation en relation à risques accrus nécessitant une revue complète.", v: true, e: "Exact : un changement de profil (lien avec un PEP étranger découvert a posteriori) déclenche une réévaluation complète de la relation. Même une relation de 15 ans sans incident doit être réexaminée sous ce nouvel angle." },
      { s: "M. Müller est RM. Il soupçonne que CHF 2 millions reçus d'un compte à Panama appartiennent à un autocrate d'Asie Centrale. Il décide d'attendre la confirmation d'une enquête judiciaire panaméenne avant de communiquer au MROS.", v: false, e: "Faux : l'art. 9 LBA impose une communication dès que l'IF 'sait ou présume' — sans attendre une enquête judiciaire étrangère. L'attente délibérée constitue une violation de l'obligation de communication 'sans délai'." },
      { s: "Une banque qui vient de communiquer au MROS pour un client doit immédiatement informer ce client de cette communication, afin de respecter son droit à l'information.", v: false, e: "Faux : l'interdiction de 'tipping off' (art. 10 al. 2 LBA) est absolue — informer le client permettrait la fuite des fonds ou la destruction de preuves. Le client ne doit PAS être informé de la communication." },
      { s: "Après avoir communiqué au MROS et bloqué les avoirs, la banque apprend que son client est en réalité un joueur de poker professionnel dont les gains sont légaux. La banque risque des sanctions pour communication injustifiée.", v: false, e: "Faux : art. 11 LBA — la protection de bonne foi est totale. Une communication fondée sur un soupçon raisonnable, qui s'avère ensuite non fondée, n'engage pas la responsabilité de l'IF." },
      { s: "Une banque a identifié une transaction suspecte de CHF 800'000. Elle procède à des clarifications internes pendant 4 semaines, puis communique au MROS. Les fonds ont quitté la banque pendant ce délai. L'IF a violé l'obligation de communication 'sans délai'.", v: true, e: "Exact : art. 9 LBA impose une communication 'sans délai' — 4 semaines de clarifications pendant lesquelles les fonds peuvent fuir est excessif. L'IF doit bloquer les fonds dès que le soupçon est fondé et communiquer rapidement." },
      { s: "goAML est la plateforme informatique développée par l'ONUDC, utilisée par le MROS pour recevoir les communications des IF de manière standardisée et sécurisée.", v: true, e: "Exact : goAML est la plateforme internationale de l'ONUDC adoptée par le MROS — elle permet une transmission standardisée et sécurisée des communications des IF vers la cellule de renseignement financier suisse." },
      { s: "Le MROS est une autorité policière dotée de pouvoirs d'arrestation et de perquisition.", v: false, e: "Faux : le MROS est une autorité administrative de réception et d'analyse — il est rattaché à fedpol mais n'a ni pouvoir policier d'arrestation, ni pouvoir judiciaire, ni pouvoir de surveillance prudentielle. Il transmet aux autorités pénales compétentes." },
      { s: "L'art. 37 LBA prévoit des sanctions pénales pour la violation intentionnelle de l'obligation de communiquer (art. 9 LBA) et de l'obligation de blocage (art. 10 LBA).", v: true, e: "Exact : art. 37 LBA — la violation intentionnelle de ces obligations est passible de sanctions pénales. Une communication tardive délibérée ou un blocage intentionnellement omis peut engager la responsabilité pénale des personnes responsables." },
      { s: "Le MROS est membre du Groupe Egmont, réseau international de plus de 160 cellules de renseignement financier (FIU), ce qui lui permet de coopérer avec des FIU étrangères dans des enquêtes internationales.", v: true, e: "Exact : l'appartenance au Groupe Egmont permet au MROS d'échanger des informations avec les FIU du monde entier — un atout majeur pour les enquêtes LBA transfrontalières." },
      { s: "Dans le cas Victor Hugo, si la banque avait finalement conclu à un soupçon fondé, elle aurait dû simultanément communiquer au MROS et bloquer les avoirs de Rakhmat conformément aux art. 9 et 10 LBA.", v: true, e: "Exact : la communication (art. 9 LBA) et le blocage des avoirs (art. 10 LBA) sont des obligations liées — lorsque le soupçon est fondé, les deux s'imposent simultanément." },
      { s: "Une banque peut légitimement refuser de communiquer au MROS si la direction estime que le risque de perdre un client stratégique est trop élevé pour l'institution.", v: false, e: "Faux : l'obligation de l'art. 9 LBA est absolue — aucune considération commerciale ne peut la supplanter. Un refus délibéré de communiquer pour préserver une relation commerciale constitue une violation pénale (art. 37 LBA)." },
      { s: "L'art. 9 LBA (obligation de communiquer) et l'art. 305ter al. 2 CP (droit facultatif de communiquer) coexistent — le premier crée une obligation lorsque le soupçon est fondé, le second crée un droit dans les situations moins certaines.", v: true, e: "Exact : ces deux dispositions se complètent. L'art. 9 LBA = obligation absolue si soupçon fondé. L'art. 305ter al. 2 CP = droit facultatif (protection sans obligation) dans les situations de doute moins caractérisé." },
      { s: "Le MROS transmet les communications des IF aux autorités pénales après une analyse préliminaire, servant ainsi de filtre entre les IF et les autorités de poursuite pénale.", v: true, e: "Exact : le MROS reçoit, analyse et filtre les communications — il ne transmet aux autorités pénales que les cas présentant une plausibilité suffisante. Ce rôle de filtre protège les autorités pénales d'être submergées par des communications non fondées." },
      { s: "Dans le cas Victor Hugo, si Shiva (RM) avait immédiatement clôturé le compte de Rakhmat dès la découverte du lien PEP, sans communiquer au MROS, elle aurait correctement géré la situation.", v: false, e: "Faux : la clôture du compte sans communication au MROS n'est pas la procédure correcte si un soupçon fondé existe. La clôture seule peut même constituer un 'tipping off' indirect. L'IF doit d'abord clarifier, puis communiquer au MROS si le soupçon est fondé — et ne clôturer qu'ensuite." }
    ]
  }
];

// ─── NIVEAU 2 — Questions avancées ──────────────────────────────────────────
const MODULES2 = [
  {
    id: 1, titre: "Responsabilité pénale — Avancé",
    questions: [
      { s: "Depuis le 1er janvier 2016, l'autorecèle est punissable en Suisse : l'auteur d'un crime préalable peut être condamné pour avoir blanchi lui-même le produit de son infraction (art. 305bis ch. 3 CP).", v: true, e: "Exact : la révision du CP entrée en vigueur le 1er janvier 2016 a mis fin à l'impunité de l'autorecèle. Avant cette date, l'auteur du crime préalable ne pouvait pas être condamné pour blanchiment de sa propre infraction." },
      { s: "Selon l'art. 102 al. 2 CP, une entreprise peut être condamnée pour blanchiment même si aucun collaborateur individuellement identifiable n'a commis l'infraction, dès lors qu'un défaut d'organisation a rendu l'infraction possible.", v: true, e: "Exact : l'al. 2 crée une responsabilité 'primaire' de l'entreprise indépendante d'une condamnation individuelle. La condition est que l'entreprise n'ait pas pris toutes les mesures organisationnelles raisonnables — ce défaut d'organisation est lui-même l'infraction reprochée à l'entreprise." },
      { s: "Pour l'art. 305bis CP, le dol éventuel suffit : accepter l'éventualité que les fonds proviennent d'un crime est suffisant pour une condamnation, sans qu'une certitude soit nécessaire.", v: true, e: "Exact : la méconnaissance délibérée ('wilful blindness') et le dol éventuel — accepter l'éventualité que les fonds sont d'origine criminelle — suffisent. Le TF l'a confirmé dans plusieurs arrêts, dont ATF 122 IV 211." },
      { s: "Dans l'ATF 136 IV 188 (Cocoteros), le Tribunal fédéral a jugé que le crime préalable doit impérativement avoir été commis en Suisse pour fonder une poursuite pour blanchiment sur le territoire suisse.", v: false, e: "Faux : ATF 136 IV 188 établit précisément l'inverse — le crime préalable peut avoir été commis à l'étranger, à condition que cet acte aurait constitué un crime selon le droit suisse (principe de double incrimination aménagée). C'est l'arrêt de référence sur ce point." },
      { s: "Le délai de prescription de l'action pénale pour blanchiment aggravé (art. 305bis al. 2 CP) est de 15 ans, car il s'agit d'un crime (peine maximale 5 ans).", v: true, e: "Exact : le blanchiment aggravé est un crime au sens du CP. Selon l'art. 97 al. 1 lit. b CP, le délai de prescription des crimes est de 15 ans. Le délai de 10 ans s'applique aux délits, pas aux crimes." },
      { s: "Un employé qui reçoit un ordre hiérarchique explicite de ne pas communiquer au MROS est exonéré de responsabilité pénale personnelle s'il suit cet ordre.", v: false, e: "Faux : l'ordre hiérarchique illicite n'est pas un fait justificatif en droit pénal suisse. L'art. 9 LBA crée une obligation légale personnelle pour les collaborateurs désignés. L'art. 14 CP (ordre d'autorité) ne s'applique qu'aux ordres légaux." },
      { s: "L'interdiction judiciaire d'exercer une profession (art. 67 CP) prononcée contre un compliance officer peut avoir une durée de 1 à 10 ans, voire à vie en cas de récidive.", v: true, e: "Exact : depuis la révision du CP de 2015, l'art. 67 al. 1 prévoit 1 à 10 ans, et l'al. 3 prévoit une interdiction à vie en cas de récidive. Cette sanction frappe directement la capacité professionnelle du condamné." },
      { s: "L'art. 260ter CP (organisation criminelle) et l'art. 305bis CP (blanchiment) peuvent former un concours réel — participer à une organisation criminelle ne protège pas contre une condamnation supplémentaire pour blanchiment des fonds de cette organisation.", v: true, e: "Exact : les deux infractions protègent des biens juridiques distincts (ordre public vs. bon fonctionnement de la justice/confiscation). Le concours réel est possible et le juge applique la règle du concours d'infractions (art. 49 CP)." },
      { s: "La confiscation pénale (art. 70 CP) porte uniquement sur les fonds directement blanchis, pas sur les avantages économiques tirés de l'utilisation de ces fonds.", v: false, e: "Faux : l'art. 70 al. 1 CP prévoit explicitement la confiscation des valeurs patrimoniales résultant de l'infraction ET de tout avantage économique en découlant. Les bénéfices réalisés grâce aux fonds blanchis peuvent être confisqués." },
      { s: "Les sanctions administratives FINMA (ex. interdiction d'exercer selon art. 33 LFINMA) et les sanctions pénales peuvent être appliquées simultanément pour les mêmes faits sans violer le principe 'ne bis in idem'.", v: true, e: "Exact : les voies administrative et pénale sont indépendantes et poursuivent des buts différents. La CEDH a admis ce cumul sous certaines conditions (arrêt A et B c. Norvège, 2016). La FINMA peut sanctionner administrativement pendant qu'une procédure pénale est en cours." },
      { s: "Dans l'affaire Banque Reyl (2025), la FINMA a constaté de graves violations LBA en lien avec des fonds du fonds souverain malaisien 1MDB et ordonné le remboursement de CHF 6.9 millions de gains illicites.", v: true, e: "Exact : la décision FINMA 2025 contre Banque Reyl a constaté des manquements graves dans les clarifications sur l'arrière-plan économique de transactions liées à 1MDB et ordonné le remboursement de CHF 6.9 millions." },
      { s: "L'obligation de communication au MROS (art. 9 LBA) est exclusive : un IF qui a communiqué ne peut pas simultanément dénoncer les faits directement aux autorités pénales cantonales.", v: false, e: "Faux : la communication MROS et la dénonciation aux autorités pénales ne sont pas exclusives. L'art. 9 LBA impose la communication au MROS, mais l'IF peut aussi dénoncer directement en parallèle, notamment en cas d'urgence manifeste." },
      { s: "Le 'tipping off' — informer le client ou un tiers qu'une communication MROS a été déposée — est expressément interdit par l'art. 10a LBA et peut entraîner des sanctions pénales.", v: true, e: "Exact : l'art. 10a LBA interdit le tipping off. Informer un client de l'existence d'une communication MROS ou d'une investigation en cours compromettrait les enquêtes en cours et pourrait permettre la fuite des avoirs." },
      { s: "Pour engager la responsabilité pénale individuelle d'un directeur de banque pour blanchiment, il suffit de prouver sa connaissance générale de risques de blanchiment au sein de l'institution.", v: false, e: "Faux : la simple connaissance générale ne suffit pas. Il faut prouver que le directeur avait connaissance (ou accepté l'éventualité) que des valeurs spécifiques provenaient d'un crime, et qu'il a accompli ou omis un acte d'entrave à la confiscation. La responsabilité pénale requiert un lien précis entre la connaissance et l'acte incriminé." },
      { s: "Le crime préalable au blanchiment d'argent peut avoir été commis à l'étranger, y compris dans le cadre d'une infraction liée à une organisation criminelle étrangère.", v: true, e: "Exact : il n'existe aucune exigence de territorialité pour le crime préalable. ATF 136 IV 188 le confirme : fonds issus d'un crime étranger peuvent être blanchis en Suisse si l'acte constituerait un crime selon le CP suisse." },
      { s: "Le compliance officer qui, par négligence simple (inadvertance), omet d'effectuer les clarifications requises peut être condamné pour blanchiment d'argent (art. 305bis CP).", v: false, e: "Faux : l'art. 305bis CP est une infraction intentionnelle — le dol (y compris éventuel) est requis. La négligence seule ne suffit pas pour une condamnation en blanchiment. Elle peut toutefois fonder des poursuites sous l'art. 305ter CP ou des sanctions FINMA." },
      { s: "La procédure FINMA contre Julius Baer (2016) était une procédure administrative — la banque n'a pas été condamnée pénalement sous l'art. 102 CP pour ces faits.", v: true, e: "Exact : la procédure Julius Baer de 2016 était une procédure administrative FINMA (pas pénale). La FINMA a constaté des lacunes dans la gestion des risques LBA et imposé des mesures correctives, sans poursuites pénales contre l'établissement lui-même." },
      { s: "La tentative de blanchiment d'argent est punissable en droit suisse, conformément à l'art. 22 CP.", v: true, e: "Exact : l'art. 22 CP prévoit la punissabilité de la tentative pour toutes les infractions intentionnelles. Celui qui commence à exécuter un acte de blanchiment sans l'achever (ex. virement refusé) peut être condamné pour tentative de blanchiment d'argent." }
    ]
  },
  {
    id: 2, titre: "Blanchiment d'argent CP — Avancé",
    questions: [
      { s: "L'élément objectif central de l'art. 305bis CP est 'd'entraver la confiscation' des valeurs patrimoniales d'origine criminelle — et non simplement de les dissimuler.", v: true, e: "Exact : tout acte (virement, conversion, investissement immobilier) qui rend plus difficile pour les autorités de saisir les fonds réalise cet élément. La simple dissimulation sans visée anti-confiscatoire pourrait ne pas suffire à elle seule." },
      { s: "Le blanchiment 'professionnel' (art. 305bis al. 2 lit. a CP) requiert que le blanchiment constitue la source principale de revenus de l'auteur.", v: false, e: "Faux : le blanchiment professionnel ne requiert pas que ce soit la source principale de revenus. Il suffit que les actes présentent le caractère d'une activité habituelle, répétée et organisée en vue d'un gain — même accessoire." },
      { s: "Le 'trade-based money laundering' (TBML) — manipulation de prix de transfert dans des transactions commerciales — peut constituer un acte de blanchiment au sens de l'art. 305bis CP.", v: true, e: "Exact : le TBML utilise des opérations commerciales pour déplacer des valeurs illicites. La surfacturation/sous-facturation systématique visant à masquer l'origine criminelle de fonds peut constituer un acte d'entrave à la confiscation." },
      { s: "La phase d'intégration (troisième étape du blanchiment) est celle où les fonds illicites, ayant été mélangés à des flux légaux lors de l'empilage, sont réintroduits dans l'économie légale.", v: true, e: "Exact : le modèle placement → empilage (layering) → intégration est fondamental. L'intégration marque le retour des fonds sous apparence licite (achat immobilier, investissement, etc.). À ce stade, les fonds sont souvent indiscernables des fonds légitimes." },
      { s: "Un avocat suisse qui accepte sciemment des honoraires dont il sait qu'ils proviennent d'un crime peut être poursuivi pour blanchiment d'argent.", v: true, e: "Exact : l'avocat qui accepte sciemment des honoraires d'origine criminelle réalise un acte de blanchiment (il perpétue les fonds criminels). Le secret professionnel ne protège pas contre les poursuites pour blanchiment. ATF 129 IV 238 a confirmé la possibilité de condamner des avocats pour blanchiment." },
      { s: "L'autorecèle introduit en 2016 peut être appliqué rétroactivement aux faits commis avant le 1er janvier 2016.", v: false, e: "Faux : le principe de non-rétroactivité de la loi pénale (art. 2 CP) interdit d'appliquer une loi plus sévère à des faits antérieurs. L'autorecèle ne s'applique qu'aux faits postérieurs au 1er janvier 2016." },
      { s: "Depuis la révision LBA de 2016, les infractions fiscales graves (soustraction d'impôts qualifiée) peuvent constituer des crimes préalables au blanchiment d'argent.", v: true, e: "Exact : la révision de 2016 a introduit certaines infractions fiscales graves comme crimes préalables potentiels (art. 305bis al. 1bis CP). La soustraction d'impôts qualifiée selon l'art. 186 LIFD ou les dispositions cantonales équivalentes peut générer des fonds blanchissables." },
      { s: "La simple possession d'argent dont on sait qu'il provient d'un crime, sans aucun autre acte visant à masquer son origine, ne constitue jamais un blanchiment au sens de l'art. 305bis CP.", v: false, e: "Faux : le TF a retenu que la conservation de fonds criminels en connaissance de leur provenance peut réaliser l'élément objectif du blanchiment si elle s'accompagne d'une intention d'entraver la confiscation. Le contexte et l'intention sont déterminants." },
      { s: "Pour caractériser le crime préalable, il n'est pas toujours nécessaire d'identifier précisément l'infraction commise — il suffit d'établir que les fonds ne peuvent provenir que d'activités criminelles.", v: true, e: "Exact : la jurisprudence admet la preuve de l'origine criminelle par exclusion. Si les fonds ne peuvent raisonnablement avoir d'autre origine que criminelle (disproportion manifeste entre train de vie et revenus légaux, etc.), le crime préalable est établi sans identifier l'infraction précise." },
      { s: "Le montant seuil de 100'000 CHF au-delà duquel un blanchiment est qualifié d'importance 'considérable' (art. 305bis al. 2 CP) est expressément fixé par la loi.", v: false, e: "Faux : la loi ne fixe aucun montant précis. C'est la jurisprudence du Tribunal fédéral qui a établi un seuil indicatif d'environ 100'000 CHF par opération ou série d'opérations. Le texte légal utilise la notion de 'montant considérable' sans chiffre." },
      { s: "Plusieurs États peuvent poursuivre simultanément la même banque pour des faits de blanchiment transfrontaliers, car le principe ne bis in idem n'a pas de portée universelle entre États souverains.", v: true, e: "Exact : en droit international, ne bis in idem n'empêche pas des poursuites parallèles dans plusieurs États ayant une compétence juridictionnelle sur les mêmes faits. Les conventions d'entraide judiciaire régissent la coopération mais n'interdisent pas nécessairement des poursuites parallèles." },
      { s: "Un gestionnaire de fortune qui investit de bonne foi des fonds blanchis pour le compte d'un client est exonéré de responsabilité pénale s'il a respecté les procédures internes.", v: true, e: "Exact : la bonne foi et le respect des procédures internes constituent des éléments d'exonération. En l'absence de dol (connaissance ou acceptation de l'éventualité de l'origine criminelle), l'élément subjectif de l'art. 305bis CP fait défaut et la responsabilité pénale est exclue." },
      { s: "Un trustee étranger peut être poursuivi en Suisse pour blanchiment si les fonds du trust transitent par un compte bancaire suisse.", v: true, e: "Exact : les tribunaux suisses ont compétence dès lors qu'un acte de blanchiment a été accompli sur le territoire suisse (art. 7 CP — lieu de commission). Le transit de fonds par un compte suisse fonde la compétence suisse, même si l'auteur est étranger et réside à l'étranger." },
      { s: "Les valeurs de substitution (ex. un immeuble acheté avec des fonds criminels) et leurs fruits (ex. loyers perçus) ne sont pas couverts par la notion 'provenant d'un crime' de l'art. 305bis CP.", v: false, e: "Faux : la notion 'provenant d'un crime' couvre non seulement le produit direct mais aussi les valeurs de substitution et leurs fruits. Les loyers d'un bien acheté avec des fonds criminels, les dividendes d'actions achetées avec ces fonds, etc., sont tous visés." },
      { s: "La communication MROS déposée en bonne foi vaut exonération complète et automatique de toute responsabilité pénale pour l'IF concernant les actes de blanchiment déjà commis.", v: false, e: "Faux : la protection de l'art. 11 LBA couvre la communication elle-même et les actes postérieurs, mais n'efface pas les infractions déjà commises avant la communication. Si des actes de blanchiment ont été accomplis préalablement, la responsabilité peut subsister." },
      { s: "La phase d'empilage (layering) du blanchiment est généralement la plus difficile à détecter pour les intermédiaires financiers, car elle implique de multiples transactions complexes conçues pour brouiller les pistes.", v: true, e: "Exact : l'empilage consiste à multiplier les transactions (virements en cascade, conversions de devises, sociétés écrans dans plusieurs juridictions) pour rendre la traçabilité très difficile. Le placement initial et l'intégration finale sont généralement plus visibles." },
      { s: "En droit suisse, l'infraction de recel (art. 160 CP) et l'infraction de blanchiment (art. 305bis CP) ne peuvent jamais entrer en concours — l'une exclut nécessairement l'autre.", v: false, e: "Faux : un concours est possible dans certaines configurations. Les deux infractions protègent des biens juridiques différents (droit de propriété pour le recel vs. bon fonctionnement de la justice pour le blanchiment). Selon les faits, un auteur peut réaliser les deux infractions." },
      { s: "L'infraction de blanchiment est une infraction d'entrave (Vereitelungsdelikt) — l'acte incriminé est précisément le fait d'entraver l'action de l'État pour confisquer les fonds criminels.", v: true, e: "Exact : cette qualification est fondamentale en doctrine et jurisprudence suisses. Elle explique pourquoi l'élément objectif se focalise sur 'entraver la confiscation' et non sur la simple dissimulation ou la détention de fonds criminels." }
    ]
  },
  {
    id: 3, titre: "Organisation de l'IF — Avancé",
    questions: [
      { s: "La fonction de compliance LBA doit être organisationnellement séparée des unités génératrices de revenus (front office) afin de garantir son indépendance.", v: true, e: "Exact : le principe de séparation entre la compliance LBA et le front office est fondamental dans l'organisation interne requise par l'OBA FINMA. Cette séparation évite les conflits d'intérêts entre la pression commerciale et les obligations de diligence." },
      { s: "Un IF peut déléguer entièrement ses obligations LBA à un prestataire externe, y compris la responsabilité finale en cas de manquement.", v: false, e: "Faux : seule l'exécution des tâches peut être déléguée, jamais la responsabilité finale. L'IF délégant reste entièrement responsable du respect des obligations LBA. Cette responsabilité non-délégable est un principe fondamental du droit de la surveillance." },
      { s: "La LBA impose aux IF d'assurer une formation régulière de leurs collaborateurs en matière LBA, pas uniquement lors de l'entrée en fonction.", v: true, e: "Exact : l'art. 8 al. 3 OBA FINMA exige une formation continue des collaborateurs concernés. La formation initiale seule est insuffisante — les typologies de blanchiment évoluent et les équipes doivent être régulièrement sensibilisées." },
      { s: "Selon l'art. 7 LBA, le délai de conservation des documents et pièces justificatives est de 5 ans après la fin de la relation d'affaires.", v: false, e: "Faux : l'art. 7 LBA impose un délai de conservation de 10 ans après la fin de la relation d'affaires ou l'exécution de la transaction. Ce délai de 10 ans correspond au délai de prescription pénal applicable." },
      { s: "Dans un groupe bancaire, la surveillance LBA doit être assurée de manière consolidée au niveau du groupe, incluant les filiales étrangères.", v: true, e: "Exact : l'OBA FINMA impose une approche de groupe (group-wide) pour la surveillance LBA. La banque mère suisse doit s'assurer que les normes minimales sont appliquées dans l'ensemble du groupe, y compris les entités étrangères, dans le respect des lois locales." },
      { s: "Le responsable LBA (MLRO) doit disposer d'un accès direct à la direction générale et, selon la structure de l'IF, au conseil d'administration.", v: true, e: "Exact : l'indépendance du MLRO implique une ligne de reporting directe vers le niveau le plus élevé possible. Dans les grandes banques, le MLRO rapporte directement au CEO ou au conseil d'administration, sans filtrage par des unités opérationnelles." },
      { s: "La FINMA classe les intermédiaires financiers qu'elle surveille directement en 3 catégories de surveillance.", v: false, e: "Faux : la FINMA applique un système de 5 catégories de surveillance (1 à 5), du plus grand au plus petit IF, basées sur des critères comme la taille du bilan, les actifs gérés et la complexité des activités. Chaque catégorie détermine l'intensité de la surveillance." },
      { s: "La LBA s'applique aux succursales suisses de banques étrangères dans les mêmes conditions qu'aux banques suisses.", v: true, e: "Exact : les succursales suisses de banques étrangères sont des intermédiaires financiers au sens de la LBA et soumises à l'ensemble des obligations LBA suisses. Elles ne peuvent pas invoquer les règles LBA de leur pays d'origine pour s'y soustraire." },
      { s: "La documentation des clarifications effectuées dans le cadre des diligences LBA doit être conservée uniquement si une communication MROS a été déposée.", v: false, e: "Faux : la documentation des clarifications doit être conservée indépendamment de l'issue — qu'une communication ait été déposée ou non. Cette documentation permet de démontrer aux auditeurs et à la FINMA que les obligations de clarification ont été remplies." },
      { s: "Un IF doit désigner formellement un responsable LBA clairement identifié, même dans les petites structures.", v: true, e: "Exact : l'art. 24 OBA FINMA impose la désignation d'un responsable LBA dans tout IF soumis à la surveillance directe de la FINMA. La taille de l'IF détermine les ressources allouées, mais l'obligation de désignation est universelle." },
      { s: "Les intermédiaires financiers affiliés à un OAR (organisme d'autorégulation) ne sont pas soumis aux mêmes obligations LBA que les banques surveillées directement par la FINMA.", v: false, e: "Faux : les obligations LBA fondamentales sont les mêmes pour tous — elles découlent de la LBA, applicable à tous les IF. La différence réside dans l'organe de surveillance (OAR vs. FINMA directement), pas dans le contenu des obligations." },
      { s: "La FINMA peut sanctionner administrativement un IF dont le programme LBA est structurellement insuffisant, même en l'absence de cas concret de blanchiment détecté.", v: true, e: "Exact : la FINMA surveille la conformité structurelle des dispositifs LBA. Des lacunes organisationnelles, documentaires ou de formation peuvent être sanctionnées indépendamment de la réalisation concrète d'un blanchiment." },
      { s: "Un IF est tenu d'évaluer régulièrement l'efficacité globale de son programme LBA, idéalement dans le cadre d'un audit indépendant annuel.", v: true, e: "Exact : l'évaluation régulière de l'efficacité du dispositif LBA est une exigence de l'approche basée sur les risques. L'audit interne ou externe du programme LBA permet d'identifier les lacunes et de les corriger avant qu'elles ne donnent lieu à des sanctions." },
      { s: "Dans les groupes financiers, les normes LBA du pays d'accueil d'une filiale étrangère prévalent toujours sur les normes LBA du groupe établies en Suisse.", v: false, e: "Faux : l'OBA FINMA exige que les normes minimales suisses soient appliquées au niveau du groupe, dans la mesure permise par les lois locales. En cas de conflit, la norme la plus stricte doit être appliquée. La filiale doit informer le groupe si la loi locale l'empêche de respecter les normes du groupe." },
      { s: "La désignation d'un nouveau responsable LBA dans une banque surveillée directement par la FINMA doit être notifiée à l'autorité de surveillance.", v: true, e: "Exact : les changements de responsable LBA dans les IF surveillés par la FINMA doivent être notifiés à la FINMA. L'autorité de surveillance doit pouvoir évaluer la compétence et l'aptitude de la personne désignée pour ce rôle central." },
      { s: "Les IF doivent procéder à une revue périodique de leurs listes de pays à risque élevé en LBA pour les aligner sur les mises à jour du GAFI et des recommandations FINMA.", v: true, e: "Exact : les listes de pays à risque évoluent régulièrement (listes noire et grise du GAFI, directives FINMA). Les IF sont tenus de maintenir leurs propres listes de pays à risque à jour et d'ajuster les profils de risque des relations concernées en conséquence." },
      { s: "Un modèle 'trois lignes de défense' (three lines of defense) bien structuré implique que les unités d'affaires (1ère ligne) délèguent leur responsabilité LBA au département compliance (2ème ligne).", v: false, e: "Faux : dans le modèle trois lignes de défense, la 1ère ligne (front office) conserve sa propre responsabilité de conformité au quotidien. La 2ème ligne (compliance, gestion des risques) surveille, conseille et contrôle. La délégation de responsabilité entre lignes est précisément ce que ce modèle vise à éviter." },
      { s: "La culture d'entreprise ('tone from the top') en matière de compliance LBA est un facteur d'évaluation pris en compte par la FINMA lors de ses inspections.", v: true, e: "Exact : la FINMA évalue non seulement les procédures écrites mais aussi la culture de conformité réelle de l'IF. Un 'tone from the top' favorable — direction qui prend au sérieux les obligations LBA — est considéré comme un indicateur clé d'un programme LBA efficace." }
    ]
  },
  {
    id: 4, titre: "Gestion des risques LBA (KYC) — Avancé",
    questions: [
      { s: "Selon l'art. 3 LBA, l'intermédiaire financier est tenu d'identifier le cocontractant pour les transactions en espèces dépassant CHF 25'000 (opérations ponctuelles).", v: true, e: "Exact : l'art. 3 al. 1 LBA fixe le seuil d'identification à CHF 25'000 pour les clients occasionnels (transactions ponctuelles). Ce seuil s'applique également aux transactions fractionnées qui paraissent liées." },
      { s: "Les documents d'identification des clients doivent être conservés pendant 5 ans après la fin de la relation d'affaires, conformément à la LBA.", v: false, e: "Faux : l'art. 7 LBA impose une conservation de 10 ans — pas 5 ans. Ce délai commence à courir à la fin de la relation d'affaires ou à l'exécution de la dernière transaction." },
      { s: "Pour les sociétés de capitaux, la CDB 20 fixe à 25% le seuil de participation à partir duquel une personne physique doit être déclarée comme ayant droit économique (ADE).", v: true, e: "Exact : le seuil de 25% des droits de vote ou du capital est le seuil standard retenu par la CDB 20 pour l'identification obligatoire de l'ADE dans les sociétés de capitaux. Ce seuil est aligné sur les recommandations GAFI et la directive européenne." },
      { s: "Une relation d'affaires initialement classifiée à 'risque faible' peut être reclassifiée à 'risque élevé' sans l'accord préalable du client.", v: true, e: "Exact : la classification du risque est une évaluation interne de l'IF — le client n'en est pas informé et son accord n'est pas requis. Si de nouveaux indices de risque apparaissent, la reclassification et l'application de diligences renforcées s'imposent immédiatement." },
      { s: "L'art. 6 LBA impose à l'IF d'effectuer des clarifications complémentaires dès qu'une transaction paraît inhabituelle ou que l'arrière-plan économique d'une relation n'est pas clair.", v: true, e: "Exact : l'art. 6 LBA est la base légale des clarifications complémentaires. Ce devoir va au-delà de l'identification initiale — il s'agit d'une obligation continue de compréhension de l'origine des fonds et du but économique des opérations." },
      { s: "Une fois l'identité d'un client vérifiée lors de l'entrée en relation, aucune re-vérification n'est nécessaire pendant toute la durée de la relation.", v: false, e: "Faux : l'approche basée sur les risques impose une mise à jour et une re-vérification périodiques des données KYC, particulièrement lors d'événements déclencheurs (changement d'ADE, nouveau produit, information adverse) ou lors des cycles de révision périodiques." },
      { s: "Pour les relations d'affaires à risque élevé, l'approbation d'un responsable de niveau senior (senior management sign-off) est requise pour entrer en relation ou maintenir la relation.", v: true, e: "Exact : l'OBA FINMA exige une approbation par la hiérarchie compétente pour les nouvelles relations à risque élevé et, selon les procédures internes, pour le maintien des relations existantes reclassifiées à risque élevé. Ce contrôle hiérarchique est une garantie de gouvernance." },
      { s: "L'identification des personnes physiques qui agissent au nom d'une personne morale (signataires autorisés, représentants légaux) est une obligation expressément prévue par l'art. 3 al. 2 LBA.", v: true, e: "Exact : l'art. 3 al. 2 LBA prévoit l'identification des représentants des personnes morales, en plus de l'identification de la personne morale elle-même. Cette double identification (entité + représentants) est fondamentale pour éviter l'utilisation de prête-noms." },
      { s: "Un IF peut se reposer entièrement sur les diligences KYC effectuées par une banque correspondante, sans procéder à ses propres vérifications, si cette banque est soumise à des obligations LBA équivalentes.", v: false, e: "Faux : même en cas de délégation ou de recours à une autre institution (art. 28 LBA), l'IF délégant reste responsable du respect des obligations LBA. Il doit s'assurer de la qualité des diligences effectuées et conserver la responsabilité finale — la délégation ne transfère pas la responsabilité." },
      { s: "L'identification de l'ayant droit économique d'une association ou fondation doit inclure les personnes physiques qui en exercent le contrôle effectif, même en l'absence de participation formelle au capital.", v: true, e: "Exact : pour les entités sans capital (associations, fondations), le critère de contrôle effectif remplace celui de la participation au capital. Les membres du comité directeur, les fondateurs et toute personne exerçant une influence déterminante doivent être identifiés." },
      { s: "La surveillance continue des transactions n'est obligatoire que pour les relations classifiées à risque élevé — les relations à faible risque en sont exemptées.", v: false, e: "Faux : la surveillance des transactions s'applique à toutes les relations d'affaires, quelle que soit leur classification de risque. L'intensité de la surveillance est proportionnelle au risque, mais l'obligation elle-même est universelle." },
      { s: "Des transactions structurées en plusieurs opérations d'un montant légèrement inférieur au seuil de déclaration (ex. CHF 24'900 répétés) doivent être traitées comme une tentative de contournement des obligations LBA.", v: true, e: "Exact : le 'structuring' — fractionnement délibéré de transactions pour passer sous les seuils de déclaration — est un red flag classique reconnu par le GAFI et l'OBA FINMA. Ces transactions doivent déclencher des clarifications approfondies et, si le soupçon est fondé, une communication MROS." },
      { s: "La vérification de l'identité d'un client peut être effectuée à distance (identification à distance) sans présentation physique de documents, sous réserve de mesures compensatoires adéquates.", v: true, e: "Exact : l'identification à distance est admise sous l'OBA FINMA et la CDB 20 si des mesures compensatoires appropriées sont en place (vidéo-identification certifiée, signatures électroniques qualifiées, vérification renforcée des documents). La présentation physique n'est plus une exigence absolue." },
      { s: "L'obligation de clarification complémentaire (art. 6 LBA) est satisfaite dès que le client fournit une explication, même non vérifiée.", v: false, e: "Faux : l'art. 6 LBA exige des clarifications suffisantes pour que l'IF comprenne l'arrière-plan économique. Les explications du client doivent être plausibles et, dans les cas à risque élevé, étayées par des pièces justificatives. Une simple déclaration verbale non vérifiée ne suffit généralement pas." },
      { s: "Pour les relations avec des entités domiciliées dans des pays figurant sur la liste noire du GAFI, les diligences renforcées sont automatiquement requises selon l'OBA FINMA.", v: true, e: "Exact : l'OBA FINMA prévoit que les relations avec des contreparties dans des pays à risque élevé selon le GAFI (liste noire = High-Risk Jurisdictions Subject to a Call for Action) déclenchent automatiquement des diligences renforcées." },
      { s: "Un intermédiaire financier doit établir un profil de risque individualisé pour chaque relation d'affaires.", v: true, e: "Exact : l'approche basée sur les risques (ABR) imposée par la LBA et l'OBA FINMA requiert une évaluation individuelle du risque pour chaque relation. Ce profil de risque détermine l'intensité des diligences applicables (standard, simplifiées ou renforcées)." },
      { s: "L'extraction de ressources naturelles (pétrole, mines) et le secteur de la construction sont des secteurs présentant un risque LBA structurellement élevé reconnu par le GAFI.", v: true, e: "Exact : le GAFI identifie ces secteurs comme présentant un risque élevé de corruption et de blanchiment d'argent. Les IF qui gèrent des fonds liés à ces secteurs, surtout dans des pays à gouvernance faible, doivent appliquer une vigilance accrue." },
      { s: "La vérification d'un extrait du registre du commerce suffit à compléter l'identification KYC d'une personne morale.", v: false, e: "Faux : l'extrait du registre du commerce identifie l'entité légale, mais l'identification KYC complète exige aussi l'identification des représentants légaux, de l'ADE, de l'objectif économique de la relation, de la provenance des fonds et d'autres diligences proportionnelles au risque." }
    ]
  },
  {
    id: 5, titre: "Structures complexes — Avancé",
    questions: [
      { s: "L'art. 9a OBA FINMA, introduit lors de la révision de 2020, impose des diligences renforcées pour les structures à plusieurs niveaux d'entités juridiques dont la transparence est insuffisante.", v: true, e: "Exact : l'art. 9a OBA FINMA est la réponse réglementaire aux Panama Papers (2016) et au rapport GAFI de 2016 sur la Suisse. Il impose à l'IF de comprendre et documenter les raisons économiques légitimes d'une structure complexe." },
      { s: "Une structure est automatiquement qualifiée de 'complexe' au sens de l'OBA FINMA dès qu'elle comporte plus de trois niveaux d'entités juridiques interposées.", v: false, e: "Faux : la qualification de 'structure complexe' n'est pas purement quantitative. Elle repose sur le critère de l'opacité et de l'absence de justification économique transparente. Une structure à 4 niveaux avec une justification claire peut ne pas être 'complexe', alors qu'une structure à 2 niveaux opaque peut l'être." },
      { s: "Face à une structure complexe, l'IF doit documenter les raisons économiques légitimes pour lesquelles le client utilise cette structure plutôt que de détenir directement les actifs.", v: true, e: "Exact : c'est l'essence de l'art. 9a OBA FINMA. L'absence de justification économique claire est en soi un signal d'alarme. L'IF doit pouvoir démontrer à l'auditeur et à la FINMA qu'il a compris et évalué la structure." },
      { s: "Pour un trust discrétionnaire, l'absence de bénéficiaires individuellement identifiés dispense l'IF de toute identification des parties au trust.", v: false, e: "Faux : même pour un trust discrétionnaire, l'IF doit identifier le constituant (settlor), le trustee, le protecteur (s'il existe) et les bénéficiaires dans la mesure du possible. Si les bénéficiaires ne sont pas encore déterminés, leur catégorie doit être documentée et une mise à jour effectuée dès qu'ils sont identifiables." },
      { s: "Le formulaire S de la CDB 20 est spécifiquement destiné aux trusts et structures fiduciaires, quelle que soit leur juridiction d'origine.", v: true, e: "Exact : le formulaire S de la CDB 20 s'applique aux trusts et structures fiduciaires analogues de toutes les juridictions — pas uniquement les trusts de droit anglo-saxon. Il couvre également les Anstalten et fondations du Liechtenstein utilisées à des fins similaires." },
      { s: "Les sociétés nominées (nominees) utilisées pour masquer l'identité du vrai propriétaire constituent un red flag majeur nécessitant des clarifications approfondies selon l'art. 9a OBA FINMA.", v: true, e: "Exact : l'utilisation de nominees — actionnaires ou dirigeants formels agissant pour le compte d'un tiers — est précisément le type d'opacité visé par l'art. 9a OBA FINMA. L'IF doit identifier la personne qui se cache derrière la structure nominée." },
      { s: "Une société holding transparente avec des filiales dans plusieurs pays, dont la structure répond à des impératifs fiscaux et opérationnels documentés, est automatiquement qualifiée de structure complexe.", v: false, e: "Faux : la qualification de structure complexe dépend de la transparence et de la justification économique. Une holding avec une structure claire, des actionnaires identifiables et une justification documentée (réglementation fiscale, organisation opérationnelle) n'est pas automatiquement une structure complexe problématique." },
      { s: "Les Panama Papers (2016) ont directement conduit à l'introduction de l'art. 9a OBA FINMA lors de la révision de 2020.", v: true, e: "Exact : les révélations des Panama Papers (~215'000 sociétés offshore) et le rapport GAFI de décembre 2016 sur la Suisse ont mis en lumière des lacunes dans la gestion des structures complexes. L'art. 9a OBA FINMA en est la réponse réglementaire directe." },
      { s: "Dans une structure à plusieurs niveaux, l'IF doit identifier l'ADE à travers tous les niveaux jusqu'à la personne physique ultime.", v: true, e: "Exact : le principe de 'look-through' exige de pénétrer tous les niveaux d'une structure jusqu'à identifier la ou les personne(s) physique(s) qui exercent le contrôle ou bénéficient économiquement des actifs. Il n'est pas admissible de s'arrêter au premier niveau de personne morale." },
      { s: "Les trusts de droit anglais reconnus en Suisse depuis 2007 (Convention de La Haye) ont la personnalité juridique en droit suisse.", v: false, e: "Faux : les trusts sont reconnus en Suisse depuis l'entrée en vigueur de la Convention de La Haye sur les trusts (juillet 2007), mais ils n'ont PAS la personnalité juridique en droit suisse. Le trustee agit en son propre nom, et les actifs du trust sont patrimonialement séparés de ses biens propres sans que le trust soit une personne morale." },
      { s: "L'utilisation d'une structure complexe domiciliée dans un pays figurant sur la liste grise du GAFI aggrave significativement le profil de risque de la relation d'affaires.", v: true, e: "Exact : la combinaison d'une structure complexe (opacité de propriété) avec une domiciliation dans un pays sous surveillance GAFI est un facteur aggravant majeur. Ces deux éléments de risque se cumulent et imposent des diligences renforcées approfondies." },
      { s: "Une fois les diligences renforcées effectuées et une structure complexe documentée, aucune surveillance continue spécifique de cette structure n'est requise.", v: false, e: "Faux : la documentation et les diligences initiales ne dispensent pas d'une surveillance continue. L'IF doit s'assurer que la justification économique de la structure reste valide, que l'ADE n'a pas changé, et que le comportement transactionnel correspond au profil documenté." },
      { s: "L'absence de justification économique claire pour l'utilisation d'une structure complexe constitue en soi un motif de refus ou de résiliation de la relation d'affaires.", v: true, e: "Exact : si l'IF ne peut pas comprendre l'arrière-plan économique d'une structure complexe malgré des clarifications répétées, l'art. 9a OBA FINMA et l'art. 6 LBA lui imposent de refuser d'entrer en relation ou d'y mettre fin. L'incompréhension persistante est un signal d'alarme rédhibitoire." },
      { s: "Une fondation de famille liechtensteinoise dont le fondateur est décédé ne nécessite plus d'identification de l'ADE, car la relation s'est éteinte avec le fondateur.", v: false, e: "Faux : le décès du fondateur ne met pas fin aux obligations KYC. L'IF doit identifier les nouveaux ayants droit économiques (bénéficiaires, conseil de fondation) et mettre à jour la documentation. Le changement de situation est précisément un événement déclencheur de révision." },
      { s: "Les sociétés cotées sur des bourses reconnues bénéficient d'une exemption permettant de ne pas identifier leur ADE dans le cadre des obligations LBA.", v: true, e: "Exact : les sociétés cotées sur une bourse reconnue (ex. SIX, NYSE, LSE) bénéficient d'une exemption d'identification de l'ADE dans la CDB 20 et l'OBA FINMA, car leur actionnariat est réputé transparent via les obligations d'annonce boursière. Cette exemption ne dispense toutefois pas d'autres diligences LBA." },
      { s: "L'art. 9a OBA FINMA impose à l'IF de s'assurer que la structure complexe 'a du sens' économiquement — des sociétés écrans sans substance ni activité réelle constituent une alarme majeure.", v: true, e: "Exact : c'est précisément le test imposé par l'art. 9a OBA FINMA. Les sociétés 'coquilles vides' (shell companies) sans employés, sans activité réelle, sans locaux — souvent utilisées uniquement pour masquer la propriété — doivent déclencher des investigations approfondies." },
      { s: "Un IF qui découvre a posteriori qu'une structure complexe qu'il gère avait pour but de dissimuler l'identité d'un trafiquant de stupéfiants est exonéré de responsabilité s'il peut prouver qu'il a rempli ses obligations de diligence.", v: true, e: "Exact : si l'IF a effectué toutes les diligences requises (identification, clarifications, surveillance) et que le client l'a délibérément trompé, la bonne foi de l'IF constitue une défense. C'est pourquoi la documentation rigoureuse des diligences est fondamentale." },
      { s: "La délégation des diligences KYC pour une structure complexe à un cabinet d'avocats étranger dispense l'IF de toute responsabilité pour les manquements de ce cabinet.", v: false, e: "Faux : comme pour toute délégation LBA, l'IF délégant reste entièrement responsable. Si le cabinet d'avocats commet des manquements dans les diligences déléguées, la responsabilité de l'IF reste engagée. L'IF doit superviser la qualité des diligences déléguées et conclure des accords formels à cet effet." }
    ]
  },
  {
    id: 6, titre: "Analyse du risque LBA — Avancé",
    questions: [
      { s: "Les pays inscrits sur la liste noire du GAFI (High-Risk Jurisdictions Subject to a Call for Action) déclenchent automatiquement des diligences renforcées pour les IF suisses selon l'OBA FINMA.", v: true, e: "Exact : l'OBA FINMA prévoit que les relations avec des entités dans des pays classés à risque élevé par le GAFI (liste noire : actuellement Corée du Nord et Iran) déclenchent des diligences renforcées obligatoires, sans évaluation individuelle préalable." },
      { s: "Les pays sur la liste grise du GAFI (Jurisdictions Under Increased Monitoring) requièrent le même niveau de diligences que les pays sur la liste noire.", v: false, e: "Faux : la liste grise et la liste noire ont des implications différentes. La liste noire exige une vigilance maximale (parfois équivalente à une interdiction de relations), tandis que la liste grise requiert des diligences renforcées proportionnelles au risque spécifique. Les deux ne sont pas équivalentes." },
      { s: "Une adverse media défavorable (article de presse faisant état de corruption) concernant un client constitue un événement déclencheur de réévaluation de son profil de risque.", v: true, e: "Exact : l'adverse media screening est une composante standard du monitoring KYC. La découverte d'informations négatives dans les médias constitue un événement déclencheur (trigger event) imposant une réévaluation immédiate du profil de risque et, le cas échéant, des clarifications complémentaires." },
      { s: "La banque correspondante (correspondent banking) présente systématiquement un risque LBA inférieur à une relation d'affaires directe avec un client privé.", v: false, e: "Faux : le correspondent banking peut présenter des risques LBA élevés, notamment via les 'nested accounts' (comptes imbriqués) qui permettent à des clients inconnus d'accéder indirectement au système financier. Le GAFI identifie le correspondent banking comme une zone de risque élevé nécessitant des diligences spécifiques." },
      { s: "Dans l'approche basée sur les risques (ABR), les ressources compliance doivent être concentrées sur les relations et transactions présentant les risques les plus élevés.", v: true, e: "Exact : le principe fondateur de l'ABR est la proportionnalité. Les ressources limitées de compliance doivent être allouées en priorité là où le risque est le plus élevé — relations avec des PEPs, pays à risque, transactions complexes — et non de manière uniforme à toutes les relations." },
      { s: "Un client qui réalise des transactions régulières d'un montant légèrement inférieur au seuil de déclaration (CHF 24'800 répétés) présente un profil de risque normal si ces transactions correspondent à son activité déclarée.", v: false, e: "Faux : même si le montant unitaire correspond à l'activité déclarée, la régularité à un montant juste en dessous du seuil est un signal classique de 'structuring' (fractionnement délibéré). Ce comportement doit être documenté et, s'il est inexpliqué, faire l'objet de clarifications." },
      { s: "Le risque de financement du terrorisme (FT) doit faire l'objet d'une évaluation distincte du risque de blanchiment dans le programme LBA d'un IF.", v: true, e: "Exact : bien que blanchiment et financement du terrorisme partagent des mécanismes communs, leurs caractéristiques diffèrent (montants souvent faibles pour le FT, pas nécessairement issus d'un crime). L'OBA FINMA requiert une analyse séparée du risque FT, notamment pour les produits et services susceptibles d'être utilisés à ces fins." },
      { s: "Le risque LBA d'une relation est déterminé uniquement par les caractéristiques du client (nationalité, profession, PEP) — les produits utilisés et les transactions effectuées n'entrent pas dans l'évaluation.", v: false, e: "Faux : le profil de risque d'une relation est multidimensionnel. Il intègre : (1) le profil du client (nationalité, profession, PEP, structure), (2) le profil géographique (pays de domicile, origine des fonds), (3) le profil produit/service (private banking, cash, cryptomonnaies), et (4) le profil transactionnel." },
      { s: "Un gérant de fortune indépendant (GFI) qui apporte des clients présente un risque LBA spécifique lié au fait que la banque dépositaire ne connaît pas les clients finaux du GFI.", v: true, e: "Exact : le modèle GFI crée un risque d'interposition — la banque dépositaire gère des actifs pour des clients qu'elle ne connaît pas directement. L'OBA FINMA impose des diligences spécifiques pour ces relations (identification des clients finaux, due diligence sur le GFI lui-même)." },
      { s: "Une notation de risque interne 'faible' attribuée à un client ne peut être modifiée que si le client donne son accord.", v: false, e: "Faux : la notation de risque est une évaluation interne de l'IF — le client n'en est pas informé et son accord n'est ni requis ni sollicité. L'IF peut modifier la notation à tout moment en fonction de nouvelles informations, sans contrainte contractuelle envers le client." },
      { s: "La mise à jour de la liste des pays à risque élevé (ex. nouvelles inscriptions sur la liste grise GAFI) doit déclencher une révision des relations d'affaires avec des contreparties dans ces pays.", v: true, e: "Exact : le suivi des listes GAFI est une obligation opérationnelle concrète pour les IF. Lorsqu'un pays est ajouté à la liste grise ou noire, les IF doivent identifier et réévaluer leurs relations d'affaires avec des contreparties dans ce pays." },
      { s: "Le risque inhérent d'un produit (ex. compte numéroté en private banking) est identique au risque résiduel après application des contrôles.", v: false, e: "Faux : le risque inhérent (potentiel de risque du produit indépendamment des contrôles) diffère du risque résiduel (risque subsistant après application des mesures de mitigation). Un produit à risque inhérent élevé peut avoir un risque résiduel acceptable si les contrôles compensatoires sont robustes." },
      { s: "Un pays présentant un régime fiscal privilégié (juridiction offshore) constitue en soi un facteur de risque LBA devant être pris en compte dans l'évaluation du risque.", v: true, e: "Exact : la domiciliation dans une juridiction offshore est un facteur de risque reconnu. Elle peut faciliter l'opacité de la propriété et l'organisation de structures complexes. Ce facteur seul ne justifie pas un refus, mais doit être intégré dans l'évaluation globale du risque de la relation." },
      { s: "La FINMA peut sanctionner un IF qui n'a pas réévalué le risque d'une relation malgré des signaux d'alarme manifestes, même si aucun blanchiment n'a été établi.", v: true, e: "Exact : la FINMA sanctionne les manquements structurels et procéduraux au dispositif LBA, indépendamment de la réalisation d'un blanchiment concret. L'omission de réévaluer le risque face à des signaux d'alarme évidents constitue une violation des obligations de diligence." },
      { s: "Les sociétés cotées sur des bourses reconnues sont entièrement exemptes de toute évaluation des risques LBA.", v: false, e: "Faux : si l'identification de l'ADE des sociétés cotées bénéficie d'une exemption dans certains cas, l'évaluation globale du risque LBA de la relation reste obligatoire. Le type de transactions, les produits utilisés et le comportement transactionnel doivent toujours être évalués." },
      { s: "Dans une relation de private banking avec un client fortuné, la complexité et le volume des avoirs en eux-mêmes constituent des facteurs de risque LBA.", v: true, e: "Exact : la fortune importante et la complexité des structures patrimoniales sont des facteurs de risque reconnus. Le private banking de haute valeur nette est un segment identifié comme présentant des risques LBA élevés, notamment pour le blanchiment de fonds d'origine criminelle ou de corruption." },
      { s: "L'approche basée sur les risques (ABR) permet à un IF d'appliquer des diligences simplifiées pour toutes les relations d'affaires, dès lors qu'il documente sa méthodologie.", v: false, e: "Faux : l'ABR permet des diligences simplifiées UNIQUEMENT pour les relations à risque faible avéré. Elle impose des diligences renforcées pour les risques élevés et des diligences standard pour les risques moyens. L'ABR n'est pas une carte blanche pour simplifier systématiquement toutes les diligences." },
      { s: "Le suivi régulier de l'actualité (news screening) sur les clients est une composante attendue d'un dispositif KYC performant selon les standards internationaux.", v: true, e: "Exact : l'adverse media monitoring (suivi de l'actualité négative sur les clients) est un standard GAFI et une pratique reconnue par la FINMA. Il complète les vérifications initiales et permet de détecter des changements de profil de risque entre deux révisions périodiques." }
    ]
  },
  {
    id: 7, titre: "Surveillance des transactions — Avancé",
    questions: [
      { s: "Un système de surveillance des transactions (TMS) doit être calibré en fonction du profil de risque spécifique de l'IF — les paramètres standard génériques ne suffisent pas.", v: true, e: "Exact : l'OBA FINMA exige une calibration du TMS adaptée aux risques spécifiques de l'IF (types de clients, produits offerts, canaux de distribution). Des paramètres génériques non ajustés peuvent générer un excès de faux positifs ou, pire, laisser passer des transactions réellement suspectes." },
      { s: "La LBA impose à tous les IF, quelle que soit leur taille, l'implémentation d'un système de surveillance des transactions (TMS) entièrement automatisé.", v: false, e: "Faux : l'obligation est proportionnée à la taille et à la complexité de l'IF. Les petits IF peuvent utiliser des processus manuels ou semi-automatisés si ceux-ci sont efficaces. Ce qui est requis, c'est la surveillance effective des transactions, pas nécessairement un système entièrement automatisé." },
      { s: "La décision de fermer une alerte de surveillance comme 'non suspecte' doit être documentée avec la justification de cette décision, et conservée conformément aux obligations de rétention.", v: true, e: "Exact : la documentation des décisions sur les alertes (ouverture, investigation, clôture avec justifications) est obligatoire. Cette traçabilité permet à la FINMA et aux auditeurs de vérifier que les alertes ont été traitées sérieusement et selon les procédures." },
      { s: "La surveillance des transactions doit couvrir les transactions individuelles mais aussi les comportements transactionnels sur la durée (ex. changement de volume sur 12 mois).", v: true, e: "Exact : la surveillance comportementale (analyse des tendances sur la durée) complète la surveillance des transactions individuelles. Un client dont le volume de transactions double sans explication, même si chaque transaction individuelle est sous les seuils d'alerte, doit déclencher une investigation." },
      { s: "L'obligation de surveillance des transactions porte uniquement sur les virements internationaux — les transactions domestiques ne sont pas soumises à monitoring.", v: false, e: "Faux : toutes les transactions sont soumises à surveillance, domestiques comme internationales. Les transactions domestiques peuvent également indiquer des schémas de blanchiment (ex. virements en cascade entre comptes locaux, retraits en espèces répétés)." },
      { s: "Un IF qui identifie une transaction suspecte mais la laisse s'exécuter avant de communiquer au MROS pour ne pas alerter le client assume un risque de responsabilité significatif.", v: true, e: "Exact : l'art. 9 al. 1bis LBA impose de ne pas exécuter une transaction suspecte si la communication peut être effectuée avant. Laisser s'exécuter des transactions suspectes tout en différant la communication est contraire à l'obligation de communication 'sans délai'." },
      { s: "Une banque peut valider automatiquement et clore une alerte de surveillance générée pour un client classé 'risque faible' sans investigation approfondie.", v: false, e: "Faux : toutes les alertes doivent faire l'objet d'une investigation proportionnelle, quelle que soit la classification de risque initiale du client. Une classification initiale à risque faible ne justifie pas l'absence d'investigation sur une alerte spécifique — l'alerte peut signaler un changement de profil." },
      { s: "La notion de 'transaction inhabituelle' doit être évaluée par rapport au profil comportemental habituel du client, et non uniquement par rapport à des seuils absolus.", v: true, e: "Exact : le caractère 'inhabituel' est relatif au client. Une transaction de CHF 500'000 peut être parfaitement normale pour un client dont le portefeuille est de CHF 50 millions, mais inhabituelle pour un client avec un portefeuille de CHF 100'000. La référence au profil individuel est fondamentale." },
      { s: "Les transferts de fonds impliquant des cryptomonnaies sont soumis aux obligations de surveillance des transactions pour les IF suisses autorisés à gérer ces actifs.", v: true, e: "Exact : la FINMA a étendu les obligations LBA aux actifs virtuels. Les IF agréés pour les cryptomonnaies doivent appliquer les mêmes obligations de surveillance que pour les actifs traditionnels, incluant la règle de voyage (travel rule) pour les transferts." },
      { s: "Un nombre très élevé de faux positifs (alertes non fondées) dans un TMS est sans conséquence sur la qualité du dispositif de surveillance si toutes les alertes sont traitées.", v: false, e: "Faux : un taux excessif de faux positifs est problématique pour deux raisons : (1) il sature les équipes de compliance qui doivent traiter des alertes sans intérêt, réduisant la qualité des investigations sur les vraies alertes ; (2) il peut indiquer une miscalibration du TMS qui mérite correction. La FINMA l'interprète comme un signe de dispositif insuffisant." },
      { s: "L'utilisation de transactions structurées (structuring) — plusieurs transactions juste sous le seuil de déclaration — est un schéma de blanchiment reconnu qui doit être intégré dans les règles du TMS.", v: true, e: "Exact : le structuring est l'un des schémas les plus fréquemment détectés. Le TMS doit inclure des règles spécifiques pour détecter les séries de transactions proches des seuils de déclaration (ex. plusieurs transactions de CHF 24'900 dans un délai court)." },
      { s: "Les transactions internes entre clients d'un même IF ne présentent pas de risque de blanchiment et n'ont pas à être surveillées.", v: false, e: "Faux : les transactions internes (entre comptes du même IF) peuvent être utilisées pour l'empilage (layering) — multiplication des virements internes pour brouiller la traçabilité. Ces transactions doivent être surveillées au même titre que les transactions externes." },
      { s: "Le calibrage du TMS doit être revu régulièrement pour intégrer les nouvelles typologies de blanchiment et les retours d'expérience des investigations.", v: true, e: "Exact : le TMS n'est pas un outil statique. Les nouvelles typologies de blanchiment (cryptomonnaies, TBML, nouveaux schémas), les retours d'expérience des investigations et les communiqués du MROS/GAFI doivent conduire à des ajustements périodiques des règles de surveillance." },
      { s: "La surveillance des transactions en temps réel (real-time monitoring) est imposée par la LBA suisse à toutes les catégories d'IF.", v: false, e: "Faux : la LBA n'impose pas universellement le monitoring en temps réel. La surveillance peut se faire en batch (traitement différé) pour de nombreux types de transactions. Ce qui est requis, c'est que les transactions suspectes soient identifiées et traitées dans un délai raisonnable permettant l'application des mesures nécessaires." },
      { s: "La documentation des dossiers d'investigation sur les alertes de surveillance doit être conservée pendant au moins 10 ans selon les obligations LBA.", v: true, e: "Exact : comme pour tous les documents LBA (art. 7 LBA), les dossiers d'investigation des alertes doivent être conservés 10 ans. Cette documentation permet de reconstituer la chaîne des décisions prises et de démontrer le sérieux de la surveillance effectuée." },
      { s: "Une fois qu'une alerte de surveillance a été fermée comme 'non suspecte', l'IF n'a plus l'obligation de surveiller les transactions similaires de ce client à l'avenir.", v: false, e: "Faux : la surveillance continue ne s'interrompt pas après la fermeture d'une alerte. Des transactions ultérieures similaires peuvent constituer un schéma émergent. La fermeture d'une alerte ne crée pas de présomption irréfragable de légitimité pour les transactions futures." },
      { s: "L'IF doit documenter sa méthodologie de surveillance des transactions et la mettre à disposition des auditeurs et de la FINMA sur demande.", v: true, e: "Exact : la transparence sur la méthodologie de surveillance est une exigence fondamentale. La FINMA doit pouvoir évaluer si le TMS est adapté aux risques de l'IF. Cette documentation inclut les règles de calibrage, les seuils d'alerte, les procédures d'investigation et les statistiques d'efficacité." },
      { s: "Un IF qui exécute délibérément des transactions suspectes en attendant la confirmation d'une enquête judiciaire avant de bloquer les fonds respecte ses obligations LBA.", v: false, e: "Faux : l'IF ne peut pas conditionner son action à une confirmation judiciaire externe. L'art. 9 LBA impose une communication dès que le soupçon est fondé, et l'art. 10 LBA prévoit le blocage des avoirs. Attendre une enquête judiciaire pour agir constitue une violation grave des obligations LBA." }
    ]
  },
  {
    id: 8, titre: "PEPs et risques de corruption — Avancé",
    questions: [
      { s: "La définition des PEPs au sens de l'OBA FINMA inclut les hauts fonctionnaires nationaux, les dirigeants d'organisations internationales et les personnes qui leur sont proches.", v: true, e: "Exact : l'OBA FINMA définit les PEPs de manière large pour inclure les fonctionnaires de rang élevé (national et étranger), les dirigeants d'organisations internationales (FMI, ONU, etc.), ainsi que leurs proches (famille et associés). Cette définition large est alignée sur les recommandations du GAFI." },
      { s: "En Suisse, les PEPs domestiques (fonctionnaires suisses de haut rang) bénéficient depuis toujours d'un régime de diligence simplifié par rapport aux PEPs étrangers.", v: false, e: "Faux : jusqu'en 2016, les IF suisses avaient effectivement tendance à appliquer des diligences moins strictes pour les PEPs domestiques. Mais la révision de l'OBA FINMA (2016) a aligné les exigences — les PEPs domestiques sont désormais soumis aux mêmes diligences renforcées que les PEPs étrangers." },
      { s: "Les membres de la famille proche d'un PEP (conjoint, partenaire enregistré, enfants, parents) sont eux-mêmes considérés comme PEPs au sens de l'OBA FINMA.", v: true, e: "Exact : l'OBA FINMA étend la qualification PEP aux membres de la famille proche. Cette extension vise à éviter que les personnes exposées politiquement n'utilisent leurs proches comme écrans pour dissimuler des fonds d'origine corrompue." },
      { s: "Les 'proches associés' (close associates) d'un PEP — personnes entretenant des liens d'affaires étroits — peuvent également nécessiter des diligences renforcées.", v: true, e: "Exact : les proches associés d'un PEP (partenaires commerciaux, personnes partageant la propriété d'entités légales, etc.) sont inclus dans la définition élargie. Les fonds de corruption transitent souvent par ces intermédiaires de confiance." },
      { s: "Une personne cesse définitivement d'être considérée comme PEP exactement 12 mois après avoir quitté ses fonctions politiques.", v: false, e: "Faux : il n'existe pas de délai fixe légal de 12 mois. Le statut PEP après la fin des fonctions persiste aussi longtemps qu'une influence politique résiduelle peut être exercée — cette évaluation est faite au cas par cas. Pour un ancien chef d'État d'un pays à gouvernance faible, le risque peut subsister bien au-delà de 12 mois." },
      { s: "Pour entrer en relation avec un PEP, l'approbation d'un membre de la direction senior de l'IF est requise selon l'OBA FINMA.", v: true, e: "Exact : l'OBA FINMA exige une autorisation au niveau de la direction pour les relations avec des PEPs (nouveaux entrants). Cette exigence de 'sign-off' au niveau senior garantit que la décision est prise en connaissance de cause et avec une évaluation des risques appropriée." },
      { s: "Un chef d'État étranger actuellement en fonctions présente généralement un risque PEP plus faible qu'un ancien chef d'État qui a quitté ses fonctions depuis 2 ans.", v: false, e: "Faux : un dirigeant actuellement en fonctions a un accès direct et immédiat aux ressources de l'État, aux marchés publics et aux décisions gouvernementales — ce qui représente un risque plus élevé. Un ancien dirigeant peut avoir moins d'influence directe, bien que ce ne soit pas toujours le cas." },
      { s: "Dans une relation avec un PEP, l'IF doit comprendre non seulement l'identité du PEP mais aussi l'origine de son patrimoine et des fonds déposés.", v: true, e: "Exact : les diligences renforcées PEP vont au-delà de la simple identification. L'IF doit s'assurer que la fortune et les fonds sont cohérents avec la fonction exercée et les revenus légaux. Une fortune disproportionnée par rapport aux fonctions est un signal d'alarme majeur." },
      { s: "Si un client est identifié comme PEP après l'entrée en relation, l'IF peut attendre le prochain cycle annuel de révision pour appliquer les diligences renforcées.", v: false, e: "Faux : la découverte du statut PEP d'un client existant constitue un événement déclencheur (trigger event) d'application immédiate des diligences renforcées. Attendre le cycle annuel en sachant que le client est PEP constitue une violation des obligations LBA." },
      { s: "Les sanctions internationales (OFAC, UE) peuvent s'appliquer à des PEPs et créer des obligations de gel des avoirs indépendamment des obligations LBA suisses.", v: true, e: "Exact : les sanctions internationales et les obligations LBA sont des régimes distincts mais complémentaires. Un PEP peut figurer simultanément sur une liste de sanctions et présenter un risque LBA élevé. Les deux régimes doivent être gérés en parallèle — le non-respect des sanctions peut également entraîner des sanctions pénales." },
      { s: "La convention de l'OCDE sur la lutte contre la corruption d'agents publics étrangers dans les transactions commerciales internationales engage la Suisse à poursuivre les entreprises suisses qui corrompent des fonctionnaires étrangers.", v: true, e: "Exact : la Suisse a ratifié la Convention OCDE anticorruption. Les entreprises suisses peuvent être poursuivies en Suisse pour corruption active d'agents publics étrangers dans des transactions commerciales internationales (art. 322septies CP)." },
      { s: "Une fondation ou association à but non lucratif présente toujours un risque LBA inférieur à une société commerciale, en raison de son caractère non lucratif.", v: false, e: "Faux : les organisations à but non lucratif peuvent être utilisées comme véhicules de blanchiment (ex. fausses fondations caritatives pour recycler des fonds de corruption). Le GAFI identifie ce secteur comme un risque spécifique. Le caractère non lucratif ne réduit pas automatiquement le risque LBA." },
      { s: "La LBA requiert que les IF documentent précisément leur décision de classifier ou non un client comme PEP, y compris les sources consultées.", v: true, e: "Exact : la documentation de la classification PEP (positif ou négatif) est essentielle pour démontrer que l'IF a effectué la vérification requise. Elle doit inclure les sources consultées (bases de données, listes, recherches médias), la date de la vérification et la conclusion." },
      { s: "Un client ayant exercé des fonctions ministérielles il y a 10 ans dans un pays à faible gouvernance ne présente plus aucun risque PEP résiduel.", v: false, e: "Faux : l'évaluation du risque résiduel après la fin des fonctions est case-by-case. Dans un pays à faible gouvernance où les anciens ministres conservent une influence informelle significative, le risque peut subsister au-delà de 10 ans. L'IF doit documenter son évaluation de ce risque résiduel." },
      { s: "Les IF suisses doivent consulter des bases de données spécialisées (ex. World-Check, Refinitiv) ou d'autres sources pour identifier les PEPs, en plus de l'auto-déclaration du client.", v: true, e: "Exact : l'auto-déclaration du client ne suffit pas — un client PEP peut délibérément taire son statut. L'IF doit effectuer ses propres recherches via des bases de données PEP/sanctions, des sources médias et d'autres sources disponibles pour identifier indépendamment le statut PEP." },
      { s: "Le secteur pétrolier et minier dans les pays à gouvernance faible est reconnu par le GAFI comme un secteur présentant des risques structurellement élevés de corruption et de blanchiment.", v: true, e: "Exact : le GAFI et la FINMA identifient les revenus issus de ressources naturelles dans les pays à gouvernance faible comme une source de risque élevé. Les entreprises pétrolières et minières dans ces pays sont souvent liées à des pratiques de corruption et de détournement de fonds publics." },
      { s: "En cas de doute sur le statut PEP d'un client, l'IF peut accorder le bénéfice du doute au client et ne pas appliquer de diligences renforcées.", v: false, e: "Faux : en matière de PEPs, le principe de précaution prévaut. En cas de doute, l'IF doit appliquer les diligences renforcées et résoudre l'incertitude. L'approche 'bénéfice du doute au client' est incompatible avec les obligations LBA — le risque doit être présumé jusqu'à preuve du contraire." },
      { s: "Dans la Cas Victor Hugo, le fait que Rakhmat soit cliente de la banque depuis 15 ans sans incident signifie que le lien PEP découvert peut être traité lors du prochain cycle de révision annuel.", v: false, e: "Faux : la durée de la relation et l'absence d'incident passé n'exemptent pas d'une réaction immédiate lors de la découverte d'un lien PEP. Comme pour tout trigger event, la réévaluation des diligences doit être déclenchée immédiatement, indépendamment de l'historique de la relation." }
    ]
  },
  {
    id: 9, titre: "CDB 20 — Avancé",
    questions: [
      { s: "La Convention de diligence des banques (CDB 20) est une convention de droit privé entre les banques membres de l'Association suisse des banquiers (ASB) — elle n'a pas force de loi fédérale.", v: true, e: "Exact : la CDB est une convention privée entre les établissements membres de l'ASB. Elle n'est pas une loi votée par le Parlement. Son respect est contrôlé par la Commission de surveillance CDB, dont les sanctions sont de nature contractuelle et non pénale." },
      { s: "La CDB 20 est entrée en vigueur le 1er janvier 2016.", v: false, e: "Faux : la CDB 20 est entrée en vigueur le 1er janvier 2020, remplaçant la CDB 16 (en vigueur depuis 2016). La numérotation reflète l'année d'entrée en vigueur : CDB 08, CDB 16, CDB 20." },
      { s: "Le formulaire A de la CDB 20 est utilisé pour déclarer l'ayant droit économique lorsque le cocontractant est une personne agissant pour le compte d'un tiers.", v: true, e: "Exact : le formulaire A est le formulaire standard pour identifier l'ayant droit économique (personne physique) différent du cocontractant. Il est utilisé lorsque le cocontractant n'agit pas pour son propre compte." },
      { s: "Le formulaire K de la CDB 20 est destiné aux trusts et structures fiduciaires.", v: false, e: "Faux : le formulaire K est destiné aux sociétés et personnes morales opérationnelles qui déclarent agir pour leur propre compte et être elles-mêmes les ayants droit économiques. Le formulaire S est celui destiné aux trusts et structures fiduciaires similaires." },
      { s: "Selon la CDB 20, un formulaire d'identification de l'ADE doit être mis à jour si les circonstances changent de manière substantielle (ex. changement d'ADE).", v: true, e: "Exact : un changement d'ADE constitue un événement déclencheur obligeant la banque à obtenir un nouveau formulaire. La CDB 20 impose que l'identification soit maintenue à jour pour refléter la situation réelle, pas seulement lors de l'entrée en relation." },
      { s: "La Commission de surveillance CDB peut infliger des amendes allant jusqu'à CHF 10 millions par cas de violation grave de la CDB.", v: true, e: "Exact : la commission de surveillance CDB dispose d'un pouvoir de sanction significatif — jusqu'à CHF 10 millions par cas. Ces sanctions sont indépendantes des sanctions FINMA ou pénales et constituent un mécanisme d'autorégulation efficace du secteur bancaire." },
      { s: "La CDB 20 s'applique à tous les intermédiaires financiers suisses, qu'ils soient membres de l'ASB ou non.", v: false, e: "Faux : la CDB est une convention privée entre membres de l'ASB. Les IF non-bancaires (gérants de fortune indépendants, assureurs, etc.) ne sont pas directement soumis à la CDB — ils sont soumis à des obligations équivalentes via l'OBA FINMA ou leur OAR respectif." },
      { s: "Pour les transactions en espèces dépassant CHF 25'000, la banque doit identifier le cocontractant même s'il n'est pas client habituel de l'établissement.", v: true, e: "Exact : la CDB 20 et l'art. 3 LBA imposent l'identification pour les transactions en espèces au-dessus de CHF 25'000, y compris pour les clients occasionnels (non-clients). Cette obligation s'applique indépendamment de l'existence d'une relation d'affaires préexistante." },
      { s: "Le formulaire S de la CDB 20 s'applique uniquement aux trusts de droit anglo-saxon.", v: false, e: "Faux : le formulaire S couvre les trusts et structures fiduciaires de toutes les juridictions — trusts de droit anglais, américain, mais aussi les Anstalten liechtensteinois, les fondations privées à caractère fiduciaire et toute structure présentant des caractéristiques analogues à un trust." },
      { s: "Si une banque ne peut pas identifier l'ayant droit économique d'une relation d'affaires malgré ses diligences, elle doit refuser d'entrer en relation ou mettre fin à la relation existante.", v: true, e: "Exact : selon la CDB 20 et l'art. 9 OBA FINMA, l'impossibilité d'identifier l'ADE est un motif de refus ou de résiliation. L'IF ne peut pas maintenir une relation dont l'ADE est inconnu — cela serait contraire aux obligations fondamentales de connaissance du client." },
      { s: "Les banques peuvent accepter des auto-déclarations non vérifiées de l'ADE pour toutes les relations d'affaires, quelle que soit leur taille ou leur risque.", v: false, e: "Faux : si les déclarations CDB reposent sur des attestations du client, les banques doivent exercer un devoir de vérification proportionnel au risque. Pour les relations à risque élevé ou lorsque des incohérences apparaissent, des preuves documentaires complémentaires doivent être obtenues." },
      { s: "Une banque peut être sanctionnée par la commission CDB pour des violations de la CDB 20 même en l'absence de condamnation pénale ou de décision FINMA.", v: true, e: "Exact : les sanctions CDB sont indépendantes des voies pénale et FINMA. La commission CDB évalue le respect de la convention selon ses propres critères et peut sanctionner des manquements qui ne donnent lieu ni à des poursuites pénales ni à des décisions FINMA." },
      { s: "Les succursales suisses de banques étrangères ne sont pas soumises à la CDB 20.", v: false, e: "Faux : les succursales de banques étrangères qui sont membres de l'ASB sont soumises à la CDB au même titre que les banques suisses. La succursale opère en Suisse et doit respecter les standards locaux, y compris la CDB." },
      { s: "Le délai de conservation des formulaires CDB (formulaires A, K, S) est de 10 ans après la fin de la relation d'affaires.", v: true, e: "Exact : conformément à l'art. 7 LBA et aux règles CDB, les formulaires d'identification doivent être conservés 10 ans après la fin de la relation. Ce délai est aligné sur le délai de prescription pénal applicable." },
      { s: "La CDB 20 impose la présence physique du client pour toute nouvelle entrée en relation — l'identification à distance est interdite.", v: false, e: "Faux : la CDB 20 admet l'identification à distance sous certaines conditions (vidéo-identification, signature électronique qualifiée, mesures compensatoires). L'évolution technologique et la numérisation des services financiers ont conduit à assouplir l'exigence de présence physique." },
      { s: "Le formulaire A doit être obtenu dès qu'il existe un doute sur le fait que le cocontractant agit pour son propre compte.", v: true, e: "Exact : la CDB 20 impose d'obtenir le formulaire A dès que des indices laissent penser que le cocontractant pourrait agir pour un tiers. Ce seuil bas (doute suffisant) reflète le principe de précaution qui gouverne les obligations d'identification." },
      { s: "La distinction entre le formulaire A et le formulaire K repose sur la nature du bénéficiaire économique : le formulaire A identifie une personne physique tierce, le formulaire K déclare que la société cocontractante est elle-même son propre ADE.", v: true, e: "Exact : c'est la distinction fondamentale. Form A = le cocontractant identifie une personne physique différente comme ADE. Form K = la société opérationnelle déclare être elle-même son propre ADE (pas de tiers bénéficiaire)." },
      { s: "Pour les comptes numérotés, les exigences d'identification CDB sont moins strictes car l'anonymat est un avantage contractuel expressément garanti par la loi suisse.", v: false, e: "Faux : les comptes numérotés en Suisse ne confèrent pas l'anonymat légal — la banque connaît l'identité du titulaire et de l'ADE. Le numéro remplace simplement le nom dans la communication avec l'extérieur pour des raisons de discrétion interne. Les obligations CDD s'appliquent pleinement." }
    ]
  },
  {
    id: 10, titre: "Communication au MROS — Avancé",
    questions: [
      { s: "Le MROS (Bureau de communication en matière de blanchiment d'argent) est une unité administrative intégrée à fedpol (Office fédéral de la police).", v: true, e: "Exact : le MROS est la cellule de renseignement financier (CRF/FIU) suisse, rattachée à fedpol depuis 2004. Il est distinct des autorités de poursuite pénale (MPC, Ministères publics cantonaux) — c'est une cellule d'analyse et de transmission, pas de poursuite." },
      { s: "La LBA fixe un délai de 24 heures pour déposer une communication au MROS après l'identification d'une transaction suspecte.", v: false, e: "Faux : la LBA n'impose pas de délai de 24 heures. L'obligation est de communiquer 'sans délai' (art. 9 LBA) — dès que le soupçon est fondé. Ce délai non chiffré signifie que les communications tardives sans justification constituent une violation, mais aucun délai horaire précis n'est fixé dans la loi." },
      { s: "Depuis 2016, les IF utilisent le système goAML (développé par l'ONUDC) pour soumettre leurs communications au MROS par voie électronique standardisée.", v: true, e: "Exact : goAML est la plateforme internationale de l'ONUDC adoptée par le MROS. Elle permet une transmission structurée et sécurisée des communications des IF, facilitant l'analyse par le MROS et la transmission internationale via le Groupe Egmont." },
      { s: "Après réception d'une communication, le MROS peut demander des informations complémentaires à l'IF, qui est tenu de répondre (art. 22 LBA).", v: true, e: "Exact : l'art. 22 LBA donne au MROS le droit de demander des informations complémentaires à l'IF ayant communiqué. Cette obligation de coopérer avec le MROS est absolue — l'IF ne peut pas invoquer le secret bancaire pour refuser de répondre au MROS dans ce contexte." },
      { s: "Dès qu'une communication a été déposée au MROS, l'IF peut immédiatement fermer le compte et informer le client du motif de clôture.", v: false, e: "Faux : clôturer le compte et en informer le client violerait l'interdiction de tipping off (art. 10a LBA). L'IF doit maintenir la relation d'affaires pendant l'analyse par le MROS, pour ne pas alerter le client et permettre aux autorités d'agir le cas échéant." },
      { s: "L'art. 10a LBA interdit à l'IF d'informer le client ou un tiers qu'une communication MROS a été déposée à son sujet.", v: true, e: "Exact : l'interdiction de tipping off est une obligation légale absolue. La divulgation de l'existence d'une communication MROS, même indirectement (ex. fermeture soudaine d'un compte), peut constituer une violation de l'art. 10a LBA et compromettre une enquête en cours." },
      { s: "Le MROS est compétent pour engager directement des poursuites pénales à l'encontre d'un suspect après réception d'une communication.", v: false, e: "Faux : le MROS est une unité d'analyse administrative (FIU) — il n'a pas de pouvoirs de poursuite pénale. Après analyse, il transmet les cas aux autorités pénales compétentes (Ministère public de la Confédération ou ministères publics cantonaux), qui décident d'ouvrir ou non une enquête." },
      { s: "L'art. 11 LBA protège l'IF et ses collaborateurs contre toute responsabilité civile ou pénale pour une communication MROS déposée de bonne foi, même si elle s'avère non fondée.", v: true, e: "Exact : la protection de bonne foi de l'art. 11 LBA est totale pour les communications sincères. Elle couvre aussi bien les aspects pénaux (violation du secret bancaire) que civils (responsabilité envers le client). Cette protection est l'une des pierres angulaires du système de communication." },
      { s: "Si le MROS ne répond pas à une communication dans les 5 jours ouvrables, l'IF peut supposer que la communication a été rejetée et libérer les avoirs bloqués.", v: false, e: "Faux : l'absence de réponse du MROS ne signifie pas un rejet de la communication. L'IF ne peut pas libérer unilatéralement des avoirs bloqués sans autorisation formelle. Il doit maintenir les mesures de blocage jusqu'à réception d'instructions des autorités." },
      { s: "Le MROS publie des rapports annuels sur les communications reçues et les typologies détectées, qui constituent une ressource précieuse pour les IF.", v: true, e: "Exact : les rapports annuels du MROS (disponibles sur le site fedpol) fournissent des statistiques sur les communications reçues, les secteurs d'activité concernés, les infractions préalables présumées et les typologies de blanchiment. Ces rapports sont une source essentielle d'information pour calibrer les programmes LBA des IF." },
      { s: "Un IF peut déposer une communication MROS 'préventive' pour des transactions qui ne présentent pas d'indices concrets de blanchiment, uniquement pour se protéger juridiquement.", v: false, e: "Faux : les communications MROS doivent reposer sur des indices concrets et objectifs de soupçon. Des communications préventives sans fondement constituent un abus du système et peuvent surcharger le MROS sans apporter de valeur. L'art. 9 LBA requiert un 'soupçon fondé', pas une simple précaution." },
      { s: "La FINMA peut sanctionner administrativement un IF qui n'a pas communiqué au MROS malgré des indices suffisants et fondés de blanchiment.", v: true, e: "Exact : l'omission de communiquer malgré un soupçon fondé constitue une violation de l'art. 9 LBA, passible de sanctions FINMA (mesures administratives, interdiction d'exercer, amende). La FINMA et les autorités pénales peuvent sanctionner simultanément cette omission." },
      { s: "Toutes les communications MROS transmises aux autorités pénales aboutissent nécessairement à l'ouverture d'une procédure pénale formelle.", v: false, e: "Faux : les autorités pénales reçoivent les informations transmises par le MROS mais décident souverainement d'ouvrir ou non une enquête. Une proportion significative des transmissions MROS ne donne pas lieu à une procédure formelle, faute d'éléments suffisants ou de priorité des ressources." },
      { s: "Le MROS est membre du Groupe Egmont, ce qui lui permet d'échanger des informations avec plus de 160 cellules de renseignement financier étrangères.", v: true, e: "Exact : le Groupe Egmont est le réseau international des FIUs (cellules de renseignement financier). L'appartenance du MROS à ce réseau est fondamentale pour les enquêtes LBA transfrontalières — il peut échanger des renseignements financiers avec les FIUs du monde entier dans le cadre de cas spécifiques." },
      { s: "L'art. 9 LBA (obligation de communiquer) et l'art. 305ter al. 2 CP (droit facultatif de communiquer) offrent deux voies complémentaires : la première impose une obligation lorsque le soupçon est fondé, la seconde donne un droit dans les situations de doute moins caractérisé.", v: true, e: "Exact : ces deux dispositions coexistent et se complètent. L'art. 9 LBA = obligation absolue si les indices sont suffisamment fondés. L'art. 305ter al. 2 CP = droit de communiquer (avec protection légale) même sans soupçon suffisant pour déclencher l'obligation — pour les situations intermédiaires." },
      { s: "Après une communication MROS et un blocage des avoirs en vertu de l'art. 10 LBA, les fonds bloqués restent indéfiniment bloqués jusqu'à décision judiciaire.", v: false, e: "Faux : le blocage initial (art. 10 LBA) est limité dans le temps — l'art. 10 al. 4 prévoit un délai de 5 jours ouvrables. Au-delà, les autorités pénales doivent ordonner une saisie formelle pour maintenir le blocage. En l'absence d'ordre judiciaire, les fonds doivent être libérés." },
      { s: "Un IF qui a bloqué des avoirs après une communication MROS et constate ensuite que le soupçon était infondé peut être poursuivi pour immixtion illicite dans la liberté économique du client.", v: false, e: "Faux : l'art. 11 LBA protège l'IF contre toute responsabilité civile ou pénale pour les blocages effectués de bonne foi. Si l'IF avait des motifs raisonnables de soupçon au moment du blocage, sa bonne foi exclut toute responsabilité, même si le soupçon s'avère finalement non fondé." },
      { s: "Le rapport annuel du MROS indique une augmentation significative des communications reçues depuis l'introduction des infractions fiscales graves comme crimes préalables en 2016.", v: true, e: "Exact : les rapports annuels MROS montrent une progression des communications depuis 2016, en lien notamment avec l'élargissement des crimes préalables (infractions fiscales, nouvelles typologies). Cette tendance reflète aussi une meilleure sensibilisation des IF à leurs obligations de communication." }
    ]
  }
];
